"use client"

import Link from "next/link"
import { useEffect, useMemo, useState } from "react"
import { Sparkles, Loader2, Send, ListChecks, Clock, Copy, Save, Plus, RefreshCw, Users, Bell, ChevronsUpDown, Check } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { ApiSidebar } from "@/components/api-sidebar"
import { useSidebar } from "@/contexts/sidebar-context"
import { EnvironmentSelector } from "@/components/environment-selector"
import {
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu"
import { useRequestStore, type HttpMethod, type HistoryItem } from "@/hooks/use-request-store"
import { loadApiKey, saveApiKey, loadAIProvider, saveAIProvider, loadOllamaConfig, type AIProvider } from "@/hooks/use-projects-store"
import { toast } from "@/hooks/use-toast"
import { cn } from "@/lib/utils"

const PROVIDERS: { value: AIProvider; label: string }[] = [
  { value: "openai", label: "OpenAI" },
  { value: "openrouter", label: "OpenRouter" },
  { value: "anthropic", label: "Anthropic" },
  { value: "gemini", label: "Gemini" },
  { value: "ollama", label: "Ollama" },
]

const SUGGESTIONS = [
  "Donne-moi une recommandation de test API pour ce projet.",
  "Résume les routes principales de ce projet.",
  "Propose une requête de test basée sur l'historique récent.",
  "Aide-moi à corriger ce endpoint si nécessaire.",
]

const STYLE_TAGS = ["Rapide", "Précis", "Concis", "Exploratoire", "Debug"]

interface SuggestedRequest {
  title: string
  method: HttpMethod
  url: string
  queryParams?: Array<{ key: string; value: string }>
  headers?: Record<string, string>
  body?: string
  description?: string
}

interface ChatMessage {
  role: "user" | "assistant"
  content: string
}

export default function AiInsightsPage() {
  const { isCollapsed, toggleSidebar } = useSidebar()
  const { history, projects, selectedProjectId, setSelectedProject, notifications, addNotification, markNotificationRead, clearNotifications, requestSystemNotificationPermission, systemNotificationPermission } = useRequestStore()
  const selectedProject = projects.find((project) => project.id === selectedProjectId)

  const [provider, setProvider] = useState<AIProvider>(() => loadAIProvider())
  const [apiKey, setApiKey] = useState(() => loadApiKey(loadAIProvider()))
  const [isProviderConfigured, setIsProviderConfigured] = useState(false)
  const [savingConfig, setSavingConfig] = useState(false)
  const [saveStatus, setSaveStatus] = useState<string | null>(null)
  const [sendStatus, setSendStatus] = useState<string | null>(null)

  const getOllamaConfig = () => {
    const config = loadOllamaConfig()
    return {
      host: config.host || "127.0.0.1",
      port: config.port || 11434,
      model: config.model || "llama2",
    }
  }
  const [query, setQuery] = useState("")
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [loading, setLoading] = useState(false)
  const [suggestedRequest, setSuggestedRequest] = useState<SuggestedRequest | null>(null)
  const [suggestionText, setSuggestionText] = useState<string | null>(null)
  const [suggesting, setSuggesting] = useState(false)
  const [selectedHistoryRequestId, setSelectedHistoryRequestId] = useState<string | null>(null)
  const [generatedTests, setGeneratedTests] = useState<{
    jest: string
    fetch: string
    curl: string
    raw: string
  } | null>(null)
  const [generatingTests, setGeneratingTests] = useState(false)

  const currentHistory = useMemo(() => history.slice(0, 5), [history])
  const recentHistory = useMemo(() => history.slice(0, 8), [history])

  useEffect(() => {
    if (!selectedHistoryRequestId && recentHistory.length > 0) {
      setSelectedHistoryRequestId(recentHistory[0].id)
    }
  }, [recentHistory, selectedHistoryRequestId])

  const selectedHistoryRequest = useMemo(() => {
    if (recentHistory.length === 0) return null
    if (!selectedHistoryRequestId) return recentHistory[0]
    return recentHistory.find((item) => item.id === selectedHistoryRequestId) ?? recentHistory[0]
  }, [recentHistory, selectedHistoryRequestId])

  const parseGeneratedTests = (content: string) => {
    const jsonText = extractJsonBlock(content)
    try {
      return JSON.parse(jsonText)
    } catch {
      return null
    }
  }

  const handleGenerateTests = async () => {
    if (!selectedHistoryRequest) {
      toast({ title: "Sélectionne une requête pour générer des tests", variant: "destructive" })
      return
    }

    if (provider !== "ollama" && !apiKey.trim()) {
      toast({ title: "Clé API requise pour le provider choisi", variant: "destructive" })
      return
    }

    setGeneratingTests(true)
    setGeneratedTests(null)

    try {
      if (provider !== "ollama") saveApiKey(provider, apiKey)

      const prompt = `Génère trois extraits de code pour tester cette requête API et sa réponse. Retourne uniquement un JSON valide avec les champs : jest, fetch, curl. Utilise ce format exact : { \"jest\": string, \"fetch\": string, \"curl\": string }.`
      const ollamaConfig = provider === "ollama" ? getOllamaConfig() : null
      const payload = {
        provider,
        apiKey,
        model:
          provider === "anthropic"
            ? "claude-sonnet-4-20250514"
            : provider === "openai"
            ? "gpt-3.5-turbo"
            : provider === "openrouter"
            ? "openai/gpt-5.2"
            : provider === "gemini"
            ? "gemini-2.0-flash"
            : ollamaConfig?.model || "llama2",
        host: ollamaConfig?.host,
        port: ollamaConfig?.port,
        system: `${systemInstructions}\n
Voici la requête sélectionnée :\n- method: ${selectedHistoryRequest.method}\n- url: ${selectedHistoryRequest.endpoint || selectedHistoryRequest.url}\n- headers: ${JSON.stringify(selectedHistoryRequest.headers || {})}\n- body: ${selectedHistoryRequest.body || ""}\n- responseStatus: ${selectedHistoryRequest.responseStatus ?? "inconnu"}\n- responseTime: ${selectedHistoryRequest.responseTime ?? "inconnu"} ms\n\nGénère un test Jest avec supertest, un exemple Fetch natif et une commande cURL. Réponds uniquement avec du JSON.`,
        message: prompt,
      }

      const response = await fetch("/api/proxy-ai", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      })

      const rawText = await response.text()
      let data: any = {}
      try {
        data = JSON.parse(rawText)
      } catch {
        data = { content: rawText }
      }

      if (!response.ok) {
        toast({ title: data.error ?? rawText ?? "Erreur IA", variant: "destructive", meta: { event: "aiError" } } as any)
        return
      }

      const content = typeof data.content === "string" ? data.content : rawText
      const parsed = parseGeneratedTests(content) ?? (typeof data === "object" && (data.jest || data.fetch || data.curl) ? data : null)

      if (parsed && (parsed.jest || parsed.fetch || parsed.curl)) {
        setGeneratedTests({
          jest: parsed.jest ?? "",
          fetch: parsed.fetch ?? "",
          curl: parsed.curl ?? "",
          raw: content,
        })
      } else {
        setGeneratedTests({ jest: "", fetch: "", curl: "", raw: content })
      }
    } catch (error) {
      toast({ title: `Erreur IA : ${String(error)}`, variant: "destructive", meta: { event: "aiError" } } as any)
    } finally {
      setGeneratingTests(false)
    }
  }

  const routeSummary = useMemo(() => {
    if (!selectedProject) {
      if (projects.length === 0) return "Aucun projet disponible. Ajoute un projet dans Mes Projets."
      return "Sélectionne un projet actif pour voir les routes disponibles."
    }
    const routes = selectedProject.routes.slice(0, 8)
    if (routes.length === 0) return "Aucun endpoint détecté"
    return routes.map((route) => `${route.method} ${route.path}`).join("\n")
  }, [selectedProject, projects.length])

  const requestSummary = useMemo(() => {
    if (currentHistory.length === 0) return "Aucun appel récent"
    return currentHistory
      .map((item) =>
        `${item.method} ${item.endpoint} → ${item.responseStatus ?? "-"} (${item.responseTime ?? "-"}ms)`
      )
      .join("\n")
  }, [currentHistory])

  const extractJsonBlock = (text: string) => {
    const jsonBlockMatch = text.match(/```json\s*([\s\S]*?)```/i)
    if (jsonBlockMatch) return jsonBlockMatch[1]
    const firstBrace = text.indexOf("{")
    const lastBrace = text.lastIndexOf("}")
    if (firstBrace !== -1 && lastBrace !== -1) {
      return text.slice(firstBrace, lastBrace + 1)
    }
    return text
  }

  const parseSuggestedRequest = (content: string) => {
    try {
      const jsonText = extractJsonBlock(content)
      const parsed = JSON.parse(jsonText)
      if (parsed?.method && parsed?.url) {
        return parsed as SuggestedRequest
      }
    } catch {
      return null
    }
    return null
  }

  const buildFullUrl = (url: string) => {
    if (url.startsWith("http")) return url
    const base = selectedProject?.port ? `http://localhost:${selectedProject.port}` : "http://localhost"
    const normalisedUrl = url.startsWith("/") ? url : `/${url}`
    return `${base}${normalisedUrl}`
  }

  const buildCurlSnippet = (request: SuggestedRequest) => {
    const finalUrl = buildFullUrl(request.url)
    const headers = request.headers
      ? Object.entries(request.headers).map(([key, value]) => `-H "${key}: ${value}"`).join("\n      ")
      : ""
    const body = request.body ? `--data-raw '${request.body.replace(/'/g, "'\\''")}'` : ""
    return ["curl", `-X ${request.method}`, headers, body, `"${finalUrl}"`]
      .filter(Boolean)
      .join("\n      ")
  }

  const buildFetchSnippet = (request: SuggestedRequest) => {
    const finalUrl = buildFullUrl(request.url)
    const headersObject = request.headers ?? {}
    const bodyPart = request.body ? `  body: ${JSON.stringify(request.body)},\n` : ""
    return `fetch("${finalUrl}", {
  method: "${request.method}",
  headers: ${JSON.stringify(headersObject, null, 2)},
${bodyPart}})
  .then((res) => res.text())
  .then((text) => console.log(text));`
  }

  const copyToClipboard = async (text: string, label: string) => {
    try {
      await navigator.clipboard.writeText(text)
      toast({ title: `${label} copié` })
    } catch {
      toast({ title: `Impossible de copier ${label}`, variant: "destructive" })
    }
  }

  const systemInstructions = useMemo(() => {
    const selectedProjectInfo = selectedProject
      ? `Projet sélectionné : ${selectedProject.name} (${selectedProject.framework})\nPort : ${selectedProject.port ?? "inconnu"}\nRoutes détectées : ${selectedProject.routes.length}`
      : "Aucun projet sélectionné."

    return `Tu es un assistant IA global pour un outil de tests d'API. Tu disposes du contexte suivant :\n${selectedProjectInfo}\n\nRoutes détectées :\n${routeSummary}\n\nHistorique des appels :\n${requestSummary}\n\nRéponds de manière claire, concise et aide l'utilisateur à comprendre, corriger ou enrichir ses requêtes et endpoints.`
  }, [routeSummary, requestSummary, selectedProject])

  useEffect(() => {
    if (provider === "ollama") {
      setIsProviderConfigured(true)
      return
    }

    const savedProvider = loadAIProvider()
    const savedKey = loadApiKey(provider)
    setIsProviderConfigured(savedProvider === provider && savedKey.trim().length > 0)
  }, [provider])

  const handleProviderChange = (value: AIProvider) => {
    setProvider(value)
    setApiKey(loadApiKey(value))
    setIsProviderConfigured(value === "ollama" ? true : false)
    setSaveStatus(null)
    setSendStatus(null)
  }

  const handleSaveProviderConfig = async () => {
    if (provider !== "ollama" && !apiKey.trim()) {
      setSaveStatus("Clé API requise pour le provider choisi")
      toast({ title: "Clé API requise pour le provider choisi", variant: "destructive", meta: { event: "aiError" } } as any)
      return
    }

    setSavingConfig(true)
    setSaveStatus("Enregistrement de la configuration IA…")
    await new Promise((resolve) => setTimeout(resolve, 1))

    try {
      if (provider !== "ollama") saveApiKey(provider, apiKey)
      saveAIProvider(provider)
      setIsProviderConfigured(true)
      setSaveStatus(`Configuration IA enregistrée pour ${provider}`)
      toast({ title: "Configuration IA enregistrée", meta: { event: "aiResponse" } } as any)
    } catch (err) {
      setSaveStatus("Erreur lors de l'enregistrement de la configuration IA")
      toast({ title: `Erreur IA : ${String(err)}`, variant: "destructive", meta: { event: "aiError" } } as any)
    } finally {
      setSavingConfig(false)
    }
  }

  const handleSend = async () => {
    const prompt = query.trim()
    if (!prompt) return
    if (provider !== "ollama" && !isProviderConfigured) {
      setSendStatus("Enregistre la configuration IA avant d'envoyer un message.")
      toast({ title: "Enregistre la configuration IA avant d'envoyer un message.", variant: "destructive", meta: { event: "aiError" } } as any)
      return
    }

    setSendStatus("Envoi en cours...")
    const userMessage: ChatMessage = { role: "user", content: prompt }
    setMessages((prev) => [...prev, userMessage])
    try {
      addNotification?.({ title: "Message envoyé", body: prompt, type: "info" })
    } catch {}
    setQuery("")
    setLoading(true)

    try {
      if (provider !== "ollama") saveApiKey(provider, apiKey)

      const ollamaConfig = provider === "ollama" ? getOllamaConfig() : null
      const response = await fetch("/api/proxy-ai", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          provider,
          apiKey,
          model:
            provider === "anthropic"
              ? "claude-sonnet-4-20250514"
              : provider === "openai"
              ? "gpt-3.5-turbo"
              : provider === "openrouter"
              ? "openai/gpt-5.2"
              : provider === "gemini"
              ? "gemini-2.0-flash"
              : ollamaConfig?.model || "llama2",
          host: ollamaConfig?.host,
          port: ollamaConfig?.port,
          system: systemInstructions,
          message: prompt,
        }),
      })

      const rawText = await response.text()
      let data: any = {}
      try {
        data = JSON.parse(rawText)
      } catch {
        data = { content: rawText }
      }

      if (!response.ok) {
        const errorMessage =
          data.error?.message || data.error || rawText || "Erreur IA"
        const providerHint =
          provider === "openai" || provider === "openrouter"
            ? "Vérifie ta clé et ton quota sur le provider choisi."
            : "Vérifie ta configuration provider."
        const statusMessage = `${provider.toUpperCase()} error: ${errorMessage}. ${providerHint}`
        setSendStatus(statusMessage)
        toast({ title: statusMessage, variant: "destructive", meta: { event: "aiError" } } as any)
        return
      }

      const assistantContent =
        typeof data.content === "string" && data.content.trim()
          ? data.content
          : typeof rawText === "string" && rawText.trim()
          ? rawText
          : "L'IA n'a pas renvoyé de réponse. Vérifie ta configuration et réessaye."

      const assistantMessage: ChatMessage = {
        role: "assistant",
        content: assistantContent,
      }
      setMessages((prev) => [...prev, assistantMessage])
      try {
        addNotification?.({ title: "Réponse IA reçue", body: assistantContent, type: "info" })
      } catch {}
      setSendStatus("Réponse reçue")
    } catch (error) {
      const errorMessage = `Erreur IA : ${String(error)}`
      setSendStatus(errorMessage)
      toast({ title: errorMessage, variant: "destructive", meta: { event: "aiError" } } as any)
    } finally {
      setLoading(false)
    }
  }

  const handleGenerateRequest = async () => {
    if (provider !== "ollama" && !apiKey.trim()) {
      toast({ title: "Clé API requise pour le provider choisi", variant: "destructive", meta: { event: "aiError" } } as any)
      return
    }

    setSuggesting(true)
    setSuggestedRequest(null)
    setSuggestionText(null)

    try {
      if (provider !== "ollama") saveApiKey(provider, apiKey)

      const prompt = `Sur la base du projet sélectionné, des routes détectées et de l'historique d'appels, propose une requête de test concrète et prête à l'emploi. Retourne uniquement un objet JSON avec les champs : title, method, url, queryParams, headers, body, description.`

      const ollamaConfig = provider === "ollama" ? getOllamaConfig() : null
      const response = await fetch("/api/proxy-ai", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          provider,
          apiKey,
          model:
            provider === "anthropic"
              ? "claude-sonnet-4-20250514"
              : provider === "openai"
              ? "gpt-3.5-turbo"
              : provider === "openrouter"
              ? "openai/gpt-5.2"
              : provider === "gemini"
              ? "gemini-2.0-flash"
              : ollamaConfig?.model || "llama2",
          host: ollamaConfig?.host,
          port: ollamaConfig?.port,
          system: `${systemInstructions}\n
Fournis une proposition de requête dont le champ url correspond à un endpoint détecté ou à un chemin utile pour le projet.`,
          message: prompt,
        }),
      })

      const rawText = await response.text()
      let data: any = {}
      try {
        data = JSON.parse(rawText)
      } catch {
        data = { content: rawText }
      }

      if (!response.ok) {
        toast({ title: data.error ?? rawText ?? "Erreur IA", variant: "destructive", meta: { event: "aiError" } } as any)
        return
      }

      const content = data.content ?? rawText ?? ""
      const parsedRequest = parseSuggestedRequest(content)
      if (parsedRequest) {
        setSuggestedRequest(parsedRequest)
      } else {
        setSuggestionText(content)
      }
    } catch (error) {
      toast({ title: `Erreur IA : ${String(error)}`, variant: "destructive", meta: { event: "aiError" } } as any)
    } finally {
      setSuggesting(false)
    }
  }

  return (
    <div className="flex min-h-screen bg-slate-100">
      <ApiSidebar activePage="ai-insights" collapsed={isCollapsed} onCollapse={toggleSidebar} />

      <div
        className={cn(
          "flex flex-1 flex-col overflow-hidden transition-all duration-300 ease-in-out",
          isCollapsed ? "ml-[60px]" : "ml-64",
          "max-[916px]:ml-[60px]"
        )}
      >
        <header className="flex h-14 items-center justify-between border-b border-border bg-background px-6">
          <div className="flex items-center gap-2">
            <div className="flex size-8 items-center justify-center rounded border border-border">
              <div className="size-4 rounded-sm bg-foreground" />
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="grid items-center gap-2 sm:grid-cols-2">
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="outline" size="sm" className="h-8 gap-2 border-dashed font-normal">
                    <div className="size-2 rounded-full bg-slate-400" />
                    {selectedProject ? selectedProject.name : "Aucun projet"}
                    <ChevronsUpDown className="size-3 text-muted-foreground" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-[220px]">
                  <DropdownMenuLabel className="text-xs text-muted-foreground">Projets</DropdownMenuLabel>
                  <DropdownMenuSeparator />
                  {projects.map((p) => (
                    <DropdownMenuItem
                      key={p.id}
                      onClick={() => setSelectedProject(p.id)}
                      className="flex items-center gap-2"
                    >
                      <span className="truncate flex-1">{p.name}</span>
                      {selectedProjectId === p.id && <Check className="size-3.5 text-primary" />}
                    </DropdownMenuItem>
                  ))}
                </DropdownMenuContent>
              </DropdownMenu>

              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="outline" size="sm" className="h-8 gap-2 border-dashed font-normal">
                    {PROVIDERS.find((item) => item.value === provider)?.label}
                    <ChevronsUpDown className="size-3 text-muted-foreground" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-[160px]">
                  <DropdownMenuLabel className="text-xs text-muted-foreground">Provider</DropdownMenuLabel>
                  <DropdownMenuSeparator />
                  {PROVIDERS.map((item) => (
                    <DropdownMenuItem
                      key={item.value}
                      onClick={() => handleProviderChange(item.value)}
                      className="flex items-center gap-2"
                    >
                      <span className="flex-1 truncate">{item.label}</span>
                      {provider === item.value && <Check className="size-3.5 text-primary" />}
                    </DropdownMenuItem>
                  ))}
                </DropdownMenuContent>
              </DropdownMenu>
            </div>

            <div className="relative hidden md:block">
              <Input type="text" placeholder="Recherche projet, endpoint..." className="h-9 w-64 bg-muted/50 pl-3 text-sm" />
            </div>

            <EnvironmentSelector />

            <button className="flex size-9 items-center justify-center rounded-lg text-muted-foreground transition-colors hover:bg-accent hover:text-foreground">
              <Users className="size-5" />
            </button>
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <button className="relative flex size-9 items-center justify-center rounded-lg text-muted-foreground transition-colors hover:bg-accent hover:text-foreground">
                  <Bell className="size-5" />
                  {notifications && notifications.some((n) => !n.read) && (
                    <span className="absolute -top-0.5 -right-0.5 h-2 w-2 rounded-full bg-destructive" />
                  )}
                </button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-[300px]">
                <DropdownMenuLabel className="text-xs text-muted-foreground">Notifications</DropdownMenuLabel>
                <DropdownMenuSeparator />
                {(systemNotificationPermission !== "granted" && systemNotificationPermission !== "unsupported") && (
                  <div className="p-3 border-b">
                    <button
                      className="text-sm text-primary"
                      onClick={async () => {
                        try {
                          const res = await requestSystemNotificationPermission()
                          if (res === "granted") {
                            toast({ title: "Notifications système activées", meta: { event: "notificationPermission" } } as any)
                          } else if (res === "denied") {
                            toast({ title: "Permission refusée", variant: "destructive", meta: { event: "notificationPermission" } } as any)
                          }
                        } catch {}
                      }}
                    >
                      Activer notifications système
                    </button>
                  </div>
                )}
                {(!notifications || notifications.length === 0) ? (
                  <div className="p-3 text-sm text-muted-foreground">Aucune notification</div>
                ) : (
                  notifications.map((n) => (
                    <DropdownMenuItem key={n.id} onClick={() => markNotificationRead(n.id)} className="flex flex-col items-start gap-1">
                      <div className="flex items-center justify-between w-full">
                        <span className="text-sm font-medium">{n.title}</span>
                        <span className="text-xs text-muted-foreground">{new Date(n.createdAt).toLocaleTimeString()}</span>
                      </div>
                      {n.body && <div className="text-xs text-muted-foreground">{n.body}</div>}
                    </DropdownMenuItem>
                  ))
                )}
                <DropdownMenuSeparator />
                <div className="p-2">
                  <button className="text-xs text-muted-foreground" onClick={() => clearNotifications()}>Effacer</button>
                </div>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </header>

        <main className="flex-1 overflow-auto bg-slate-100 p-6">
          <div className="mx-auto flex w-full max-w-5xl flex-col gap-6 px-4">
            <section className="rounded-[32px] border border-border bg-white/95 p-6 shadow-[0_35px_60px_-30px_rgba(15,23,42,0.35)] backdrop-blur-xl">
              <div className="mb-6 rounded-[28px] border border-slate-200 bg-slate-50 p-5">
                <div className="mb-4 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                  <div>
                    <p className="text-sm font-semibold text-foreground">Générer des tests automatiques</p>
                    <p className="text-xs text-muted-foreground">
                      Basé sur une requête sélectionnée de ton historique. Obtiens un test Jest + supertest, un exemple Fetch natif et une commande cURL.
                    </p>
                  </div>
                  <Button
                    type="button"
                    onClick={handleGenerateTests}
                    disabled={!selectedHistoryRequest || generatingTests || (provider !== "ollama" && !isProviderConfigured)}
                  >
                    {generatingTests ? <Loader2 className="size-4 animate-spin" /> : "Générer les tests"}
                  </Button>
                </div>

                <div className="grid gap-4 lg:grid-cols-[0.9fr_1.1fr]">
                  <div className="space-y-4">
                    {recentHistory.length > 0 ? (
                      <div>
