import { NextRequest, NextResponse } from "next/server"

const IGNORED_FOLDERS = [
  "node_modules", ".git", ".next", "dist", "build",
  "__pycache__", ".venv", "venv", "env", "vendor",
  ".github", ".gitignore", "README.md", "LICENSE",
]

const MAX_FILES = 100
const GITHUB_API_BASE = "https://api.github.com"

interface GitHubContent {
  name: string
  path: string
  type: "file" | "dir"
  sha: string
  size?: number
  content?: string
  download_url?: string
}

export async function POST(request: NextRequest) {
  try {
    const { owner, repo, branch } = await request.json()

    if (!owner || !repo) {
      return NextResponse.json({ message: "Owner et repo requis" }, { status: 400 })
    }

    const defaultBranch = branch || await getDefaultBranch(owner, repo)
    const files = await fetchRepoFiles(owner, repo, defaultBranch)

    // Filter and decode files
    const decodedFiles: { path: string; content: string }[] = []

    for (const file of files) {
      if (file.type === "file" && file.content) {
        try {
          const content = Buffer.from(file.content, "base64").toString("utf-8")
          decodedFiles.push({ path: file.path, content })
        } catch {
          // Skip files that can't be decoded
        }
      }
      if (decodedFiles.length >= MAX_FILES) break
    }

    const framework = detectFramework(decodedFiles)
    const routes = detectRoutes(decodedFiles, framework)
    const port = detectPort(decodedFiles)

    return NextResponse.json({
      name: repo,
      framework,
      port,
      routes,
    })
  } catch (error) {
    console.error("GitHub import error:", error)
    return NextResponse.json(
      { message: error instanceof Error ? error.message : "Erreur serveur" },
      { status: 500 }
    )
  }
}

async function getDefaultBranch(owner: string, repo: string): Promise<string> {
  const res = await fetch(`${GITHUB_API_BASE}/repos/${owner}/${repo}`, {
    headers: { "Accept": "application/vnd.github.v3+json" },
  })

  if (!res.ok) throw new Error("Dépôt non trouvé ou accès refusé")

  const data = await res.json()
  return data.default_branch || "main"
}

async function fetchRepoFiles(owner: string, repo: string, branch: string): Promise<GitHubContent[]> {
  const results: GitHubContent[] = []

  async function fetchRecursive(path: string = "") {
    if (results.length >= MAX_FILES) return

    const url = `${GITHUB_API_BASE}/repos/${owner}/${repo}/contents/${path}?ref=${branch}`
    const res = await fetch(url, {
      headers: { "Accept": "application/vnd.github.v3+json" },
    })

    if (!res.ok) return

    const items: GitHubContent[] = await res.json()

    for (const item of items) {
      if (item.type === "dir" && !IGNORED_FOLDERS.some(f => item.name.includes(f))) {
        await fetchRecursive(item.path)
      } else if (item.type === "file" && item.content) {
        const ext = item.name.split(".").pop()?.toLowerCase()
        if (["js", "ts", "jsx", "tsx", "py", "php"].includes(ext || "")) {
          results.push(item)
        }
      }
    }
  }

  await fetchRecursive()
  return results
}

function detectFramework(files: { path: string; content: string }[]): string {
  const allContent = files.map(f => f.content).join("\n")

  if (/require\s*\(\s*['"]express['"]\s*\)/.test(allContent)) return "express"
  if (/from\s+fastapi\s+import/.test(allContent)) return "fastapi"
  if (/@nestjs/.test(allContent)) return "nestjs"
  if (/Route::/.test(allContent)) return "laravel"

  return "unknown"
}

function detectRoutes(files: { path: string; content: string }[], framework: string): any[] {
  const routes: any[] = []

  const EXPRESS_PATTERNS = [
    /app\.(get|post|put|delete|patch)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
    /router\.(get|post|put|delete|patch)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
  ]

  const FASTAPI_PATTERNS = [
    /@router\.(get|post|put|delete|patch)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
    /@app\.(get|post|put|delete|patch)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
  ]

  const NESTJS_PATTERNS = [
    /@(Get|Post|Put|Delete|Patch)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
  ]

  const patterns = framework === "fastapi" 
    ? FASTAPI_PATTERNS 
    : framework === "nestjs" 
      ? NESTJS_PATTERNS 
      : EXPRESS_PATTERNS

  for (const file of files) {
    for (const pattern of patterns) {
      let match
      while ((match = pattern.exec(file.content)) !== null) {
        routes.push({
          method: match[1].toUpperCase(),
          path: match[2] || "",
          sourceFile: file.path,
        })
      }
    }
  }

  return deduplicate(routes)
}

function deduplicate(routes: any[]): any[] {
  const seen = new Set<string>()
  return routes.filter(r => {
    const key = `${r.method}|${r.path}`
    if (seen.has(key)) return false
    seen.add(key)
    return true
  })
}

function detectPort(files: { path: string; content: string }[]): number | undefined {
  const all = files.map(f => f.content).join("\n")
  const match = all.match(/\.listen\(\s*(\d+)/) || all.match(/port\s*[:=]\s*(\d+)/)
  return match ? parseInt(match[1]) : undefined
}

import { NextRequest, NextResponse } from "next/server"

type ProviderBody = {
  provider: string
  apiKey?: string
  model?: string
  host?: string
  port?: string | number
  system?: string
  message?: string
}

export async function POST(req: NextRequest) {
  const body = (await req.json()) as ProviderBody
  const provider = typeof body.provider === "string" ? body.provider.trim() : ""
  const message = typeof body.message === "string" ? body.message.trim() : ""
  const apiKey = typeof body.apiKey === "string" ? body.apiKey.trim() : ""
  const model = typeof body.model === "string" ? body.model.trim() : ""
  const system = typeof body.system === "string" ? body.system : ""
  const host = typeof body.host === "string" && body.host.trim() ? body.host.trim() : "127.0.0.1"
  const port = typeof body.port === "string"
    ? body.port.trim()
    : typeof body.port === "number"
    ? String(body.port)
    : ""
  const ollamaPort = port || "11434"

  if (!provider) {
    return NextResponse.json({ error: "Missing provider" }, { status: 400 })
  }

  if (!message && provider !== "ollama") {
    return NextResponse.json({ error: "Missing message" }, { status: 400 })
  }

  if (["openai", "openrouter", "anthropic", "gemini"].includes(provider) && !apiKey) {
    return NextResponse.json({ error: "Missing API key" }, { status: 400 })
  }

  try {
    if (provider === "anthropic") {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": apiKey,
          "anthropic-version": "2023-06-01",
        },
        body: JSON.stringify({
          model: model || "claude-sonnet-4-20250514",
          max_tokens: 4096,
          system,
          messages: [{ role: "user", content: message }],
        }),
      })
      const data = await res.json()
      if (!res.ok) {
        return NextResponse.json({ error: data.error?.message ?? data.error ?? "Anthropic error" }, { status: res.status })
      }
      const contentArray = (Array.isArray(data.content) ? data.content : []) as Array<{
        type?: string
        text?: string
      }>
      const content = contentArray
        .filter((item) => item.type === "text")
        .map((item) => item.text || "")
        .join("")
      return NextResponse.json({ content })
    }

    if (provider === "openai" || provider === "openrouter") {
      const url = provider === "openai"
        ? "https://api.openai.com/v1/chat/completions"
        : "https://openrouter.ai/api/v1/chat/completions"
      const res = await fetch(url, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${apiKey}`,
        },
        body: JSON.stringify({
          model: model || (provider === "openrouter" ? "openai/gpt-5.2" : "gpt-3.5-turbo"),
          messages: [
            { role: "system", content: system },
            { role: "user", content: message },
          ],
        }),
      })
      const rawText = await res.text()
      let data: any
      try {
        data = JSON.parse(rawText)
      } catch {
        data = { error: rawText }
      }
      if (!res.ok) {
        return NextResponse.json({ error: data.error?.message ?? data.error ?? `${provider} error` }, { status: res.status })
      }
      return NextResponse.json({ content: data.choices?.[0]?.message?.content ?? data.choices?.[0]?.text ?? "" })
    }

    if (provider === "gemini") {
      const url = `https://generativelanguage.googleapis.com/v1beta/models/${model || "gemini-2.0-flash"}:generateContent?key=${apiKey}`
      const res = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          system_instruction: { parts: [{ text: system }] },
          contents: [{ parts: [{ text: message }] }],
        }),
      })
      const data = await res.json()
      if (!res.ok) {
        return NextResponse.json({ error: data.error?.message ?? data.error ?? "Gemini error" }, { status: res.status })
      }
      const content =
        data.candidates?.[0]?.content?.parts?.[0]?.text ||
        data.candidates?.[0]?.content?.text ||
        data.candidates?.[0]?.content?.[0]?.text ||
        data.candidates?.[0]?.output?.[0]?.content?.[0]?.text ||
        data.candidates?.[0]?.output?.[0]?.content ||
        data.candidates?.[0]?.content ||
        data.output?.[0]?.content?.text ||
        data.output?.text ||
        ""
      return NextResponse.json({ content })
    }

    if (provider === "ollama") {
      const res = await fetch(`http://${host}:${ollamaPort}/v1/chat/completions`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: model || "llama2",
          messages: [
            ...(system ? [{ role: "system", content: system }] : []),
            { role: "user", content: message },
          ],
        }),
      })
      const data = await res.json()
      if (!res.ok) {
        return NextResponse.json({ error: data.error?.message ?? data.error ?? "Ollama error" }, { status: res.status })
      }
      return NextResponse.json({ content: data.choices?.[0]?.message?.content ?? "" })
    }

    return NextResponse.json({ error: "Unknown provider" }, { status: 400 })
  } catch (err) {
    return NextResponse.json({ error: String(err) }, { status: 500 })
  }
}

'use client'

import { ApiSidebar } from "@/components/api-sidebar"
import { ApiHeader } from "@/components/api-header"
import { CollectionsPanel } from "@/components/collections-panel"
import { Button } from "@/components/ui/button"
import { useRequestStore, type Collection, type RequestItem } from "@/hooks/use-request-store"
import { useSidebar } from "@/contexts/sidebar-context"
import { cn } from "@/lib/utils"
import { useRouter } from "next/navigation"
import { setPendingCollectionRequest } from "@/lib/utils"
import { toast } from "@/hooks/use-toast"

function formatPath(request: RequestItem) {
  const rawPath = request.endpoint?.trim() || request.url?.trim() || "/"
  if (rawPath.startsWith("http://") || rawPath.startsWith("https://")) {
    try {
      const url = new URL(rawPath)
      return url.pathname + url.search
    } catch {
      return rawPath
    }
  }
  return rawPath.startsWith("/") ? rawPath : `/${rawPath}`
}

function buildSchemaForValue(value?: string) {
  if (!value) return { type: "string" }
  try {
    const parsed = JSON.parse(value)
    if (Array.isArray(parsed)) return { type: "array", items: { type: "object" } }
    if (typeof parsed === "object") return { type: "object" }
    if (typeof parsed === "number") return { type: "number" }
    if (typeof parsed === "boolean") return { type: "boolean" }
  } catch {
    // ignore parse error
  }
  return { type: "string" }
}

function generateOpenApiSpec(collections: Collection[]) {
  const paths: Record<string, any> = {}

  collections.forEach((collection) => {
    collection.requests.forEach((request) => {
      const path = formatPath(request)
      const method = request.method.toLowerCase()
      if (!paths[path]) paths[path] = {}

      const parameters = [
        ...(request.queryParams ?? []).map((param) => ({
          name: param.key,
          in: "query",
          required: false,
          schema: { type: "string" },
        })),
        ...Object.entries(request.headers ?? {}).map(([key, value]) => ({
          name: key,
          in: "header",
          required: false,
          schema: { type: "string" },
          description: value ? `Exemple: ${value}` : undefined,
        })),
      ]

      const requestBody = request.body
        ? {
            content: {
              "application/json": {
                schema: buildSchemaForValue(request.body),
                example: (() => {
                  try {
                    return JSON.parse(request.body)
                  } catch {
                    return request.body
                  }
                })(),
              },
            },
          }
        : undefined

      paths[path][method] = {
        tags: [collection.name],
        summary: request.name,
        description: request.url ? `URL: ${request.url}` : undefined,
        parameters,
        requestBody,
        responses: {
          "200": {
            description: "Succès",
          },
        },
      }
    })
  })

  return {
    openapi: "3.0.3",
    info: {
      title: "Zendeeps API Collections",
      version: "1.0.0",
      description: "Export OpenAPI 3.0 généré depuis les collections de requêtes.",
    },
    servers: [{ url: "http://localhost" }],
    paths,
  }
}

export default function CollectionsPage() {
  const router = useRouter()
  const { isCollapsed, toggleSidebar } = useSidebar()
  const {
    collections,
    addCollection,
    updateCollection,
    deleteCollection,
    addRequestToCollection,
    removeRequestFromCollection,
  } = useRequestStore()

  // Debug: log render and collections length to ensure re-renders occur
  if (typeof window !== 'undefined') {
    try {
       
      console.log('PAGE RENDER: collections.length =', collections.length)
    } catch {}
  }

  const handleSelectRequest = (request: RequestItem) => {
    setPendingCollectionRequest({
      name: request.name,
      method: request.method,
      url: request.url,
      endpoint: request.endpoint,
      headers: request.headers,
      body: request.body,
      queryParams: request.queryParams,
    })
    toast({ title: `Requête "${request.name}" transférée dans l'éditeur.` })
    router.push("/")
  }

  const handleSelectAndSendRequest = (request: RequestItem) => {
    setPendingCollectionRequest({
      name: request.name,
      method: request.method,
      url: request.url,
      endpoint: request.endpoint,
      headers: request.headers,
      body: request.body,
      queryParams: request.queryParams,
      sendImmediately: true,
    })
    toast({ title: `Requête "${request.name}" transférée et envoyée.` })
    router.push("/")
  }

  const handleRunCollection = (collection: Collection) => {
    if (!collection.requests.length) {
      toast({ title: `La collection "${collection.name}" est vide.`, variant: "destructive" })
      return
    }

    const firstRequest = collection.requests[0]
    setPendingCollectionRequest({
      collectionId: collection.id,
      name: firstRequest.name,
      method: firstRequest.method,
      url: firstRequest.url,
      endpoint: firstRequest.endpoint,
      headers: firstRequest.headers,
      body: firstRequest.body,
      queryParams: firstRequest.queryParams,
      sendImmediately: true,
    })
    toast({ title: `Exécution de la collection "${collection.name}" démarrée.` })
    router.push("/")
  }

  const handleRunCollectionBackground = (collection: Collection) => {
    if (!collection.requests.length) {
      toast({ title: `La collection "${collection.name}" est vide.`, variant: "destructive" })
      return
    }

    const firstRequest = collection.requests[0]
    setPendingCollectionRequest({
      collectionId: collection.id,
      name: firstRequest.name,
      method: firstRequest.method,
      url: firstRequest.url,
      endpoint: firstRequest.endpoint,
      headers: firstRequest.headers,
      body: firstRequest.body,
      queryParams: firstRequest.queryParams,
      sendImmediately: true,
      background: true,
    })
    toast({ title: `Exécution background de la collection "${collection.name}" démarrée.` })
    router.push("/")
  }

  const handleExportOpenApi = async () => {
    const spec = generateOpenApiSpec(collections)
    const contents = JSON.stringify(spec, null, 2)

    if (typeof window !== "undefined" && 'showSaveFilePicker' in window) {
      try {
        const handle = await (window as any).showSaveFilePicker({
          suggestedName: "zendeeps-openapi.json",
          types: [
            {
              description: "JSON OpenAPI file",
              accept: { "application/json": [".json"] },
            },
          ],
        })
        const writable = await handle.createWritable()
        await writable.write(contents)
        await writable.close()
        return
      } catch (error) {
        // If user cancels save dialog or browser doesn't support it, fallback to download
      }
    }

    const blob = new Blob([contents], { type: "application/json" })
    const url = URL.createObjectURL(blob)
    const link = document.createElement("a")
    link.href = url
    link.download = "zendeeps-openapi.json"
    document.body.appendChild(link)
    link.click()
    link.remove()
    URL.revokeObjectURL(url)
  }

  return (
    <div className="flex h-screen bg-background">
      <ApiSidebar activePage="collections" collapsed={isCollapsed} onCollapse={toggleSidebar} />

      <div className={cn(
        "flex flex-1 flex-col overflow-hidden transition-all duration-300 ease-in-out",
        isCollapsed ? "ml-[60px]" : "ml-64",
        "max-[916px]:ml-[60px]"
      )}>
        <ApiHeader />

        <main className="flex-1 overflow-auto">
          <div className="flex flex-col gap-4 border-b border-border bg-background/80 px-6 py-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <h1 className="text-2xl font-bold text-foreground">Collections</h1>
              <p className="text-sm text-muted-foreground">Gérez vos groupes de requêtes et exportez-les en OpenAPI.</p>
            </div>
            <div className="flex flex-wrap gap-2">
              <Button variant="secondary" onClick={handleExportOpenApi}>
                Exporter OpenAPI
              </Button>
            </div>
          </div>

          <CollectionsPanel
            collections={collections}
            onSelectRequest={handleSelectRequest}
            onSelectAndSendRequest={handleSelectAndSendRequest}
            onRunCollection={handleRunCollection}
            onRunCollectionBackground={handleRunCollectionBackground}
            onAddCollection={(data) =>
              addCollection({
                name: data?.name ?? "New Collection",
                color: data?.color ?? "emerald",
                icon: data?.icon ?? "package",
              })
            }
            onDeleteCollection={deleteCollection}
            onRenameCollection={(id, name) => updateCollection(id, { name })}
            onAddRequestToCollection={(collectionId, request) => {
              const defaultRequest = {
                name: "New Request",
                method: "GET" as const,
                url: "",
                endpoint: "",
                headers: {},
                body: "",
                queryParams: [],
              }
              addRequestToCollection(collectionId, request ?? defaultRequest)
            }}
            onRemoveRequestFromCollection={removeRequestFromCollection}
          />
        </main>
      </div>
    </div>
  )
}

