export default function SettingsPage() {
  const { isCollapsed, toggleSidebar } = useSidebar()
  const { systemNotificationPermission, requestSystemNotificationPermission, collections, environments } =
    useRequestStore()
  const [provider, setProvider] = useState<AIProvider>("openai")
  const [apiKey, setApiKey] = useState("")
  const [ollamaHost, setOllamaHost] = useState("127.0.0.1")
  const [ollamaPort, setOllamaPort] = useState("11434")
  const [ollamaModel, setOllamaModel] = useState("llama2")
  const [saveStatus, setSaveStatus] = useState<string | null>(null)
  const [showNotificationsEnabled, setShowNotificationsEnabled] = useState(false)
  const [syncModalOpen, setSyncModalOpen] = useState(false)
  const [activeSection, setActiveSection] = useState<"profile" | "ai" | "notifications" | "sync" | "account">("profile")

  // Sync active section with URL hash so sections are linkable and navigable
  useEffect(() => {
    const fromHash = window.location.hash?.replace("#", "") as
      | "profile"
      | "ai"
      | "notifications"
      | "sync"
      | "account"
      | ""
    if (fromHash) setActiveSection(fromHash || "profile")

    const onHashChange = () => {
      const h = window.location.hash?.replace("#", "") as
        | "profile"
        | "ai"
        | "notifications"
        | "sync"
        | "account"
        | ""
      if (h) setActiveSection(h || "profile")
    }

    window.addEventListener("hashchange", onHashChange)
    return () => window.removeEventListener("hashchange", onHashChange)
  }, [])

  useEffect(() => {
    try {
      if (activeSection) window.history.replaceState(null, "", `#${activeSection}`)
    } catch {}
  }, [activeSection])

  useEffect(() => {
    const configuredProvider = loadAIProvider()
    setProvider(configuredProvider)
    setApiKey(loadApiKey(configuredProvider))
    const ollamaConfig = loadOllamaConfig()
    setOllamaHost(ollamaConfig.host || "127.0.0.1")
    setOllamaPort(ollamaConfig.port?.toString() || "11434")
    setOllamaModel(ollamaConfig.model || "llama2")
  }, [])

  useEffect(() => {
    const timer = saveStatus ? window.setTimeout(() => setSaveStatus(null), 3000) : undefined
    return () => {
      if (timer) window.clearTimeout(timer)
    }
  }, [saveStatus])

  useEffect(() => {
    setShowNotificationsEnabled(
      !!systemNotificationPermission &&
        systemNotificationPermission !== "default" &&
        systemNotificationPermission !== "unsupported"
    )
  }, [systemNotificationPermission])

  const handleProviderChange = (value: AIProvider) => {
    setProvider(value)
    setApiKey(loadApiKey(value))

    if (value === "ollama") {
      const ollamaConfig = loadOllamaConfig()
      setOllamaHost(ollamaConfig.host || "127.0.0.1")
      setOllamaPort(ollamaConfig.port?.toString() || "11434")
      setOllamaModel(ollamaConfig.model || "llama2")
