function ManageEnvironmentsDialog({ open, onOpenChange, initialEditingId }: { open: boolean, onOpenChange: (open: boolean) => void, initialEditingId: string | null }) {
  const { environments, addEnvironment, updateEnvironment, deleteEnvironment } = useRequestStore()
  const [selectedId, setSelectedId] = useState<string | null>(initialEditingId || (environments.length > 0 ? environments[0].id : null))

  // Update selected if initial changes or if deleted
  if (open && initialEditingId && initialEditingId !== selectedId) {
    setSelectedId(initialEditingId)
  }

  const selectedEnv = environments.find(e => e.id === selectedId)

  const handleAddVar = () => {
    if (!selectedEnv) return
    updateEnvironment(selectedEnv.id, {
      variables: [...selectedEnv.variables, { key: "", value: "", enabled: true }]
    })
  }

  const updateVar = (index: number, field: keyof EnvironmentVariable, value: string | boolean) => {
    if (!selectedEnv) return
    const newVars = [...selectedEnv.variables]
    newVars[index] = { ...newVars[index], [field]: value }
    updateEnvironment(selectedEnv.id, { variables: newVars })
  }

  const removeVar = (index: number) => {
    if (!selectedEnv) return
    const newVars = [...selectedEnv.variables]
    newVars.splice(index, 1)
    updateEnvironment(selectedEnv.id, { variables: newVars })
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl h-[80vh] p-0 gap-0 flex overflow-hidden">
        <DialogTitle className="sr-only">Manage Environments</DialogTitle>
        {/* Left Sidebar */}
        <div className="w-1/3 border-r bg-muted/20 flex flex-col">
          <div className="p-4 border-b flex items-center justify-between">
            <h3 className="font-semibold text-sm">Environments</h3>
            <Button variant="ghost" size="icon" className="h-6 w-6" onClick={() => {
               const newId = addEnvironment({
                name: "New Environment",
                color: "slate",
                variables: []
              })
              setSelectedId(newId)
            }}>
              <Plus className="size-4" />
            </Button>
          </div>
          <div className="flex-1 overflow-y-auto p-2 space-y-1">
            {environments.map(env => (
              <button
                key={env.id}
                onClick={() => setSelectedId(env.id)}
                className={cn(
                  "w-full flex items-center gap-2 px-3 py-2 rounded-md text-sm text-left transition-colors",
                  selectedId === env.id ? "bg-accent text-accent-foreground" : "hover:bg-muted"
                )}
              >
                <div className={cn("size-2 rounded-full shrink-0", `bg-${env.color}-500`)} />
                <span className="truncate flex-1">{env.name}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Right Content */}
        <div className="flex-1 flex flex-col bg-background">
          {selectedEnv ? (
            <>
              <div className="p-4 border-b flex items-center gap-4">
                <Input 
                  value={selectedEnv.name}
                  onChange={(e) => updateEnvironment(selectedEnv.id, { name: e.target.value })}
                  className="max-w-[300px] font-semibold text-lg h-9 border-transparent hover:border-border focus-visible:border-border px-2"
                />
                <Button 
                  variant="ghost" 
                  size="icon" 
                  className="h-8 w-8 ml-auto text-destructive hover:text-destructive hover:bg-destructive/10"
                  onClick={() => {
                    if (environments.length === 1) return // Don't delete last env
                    deleteEnvironment(selectedEnv.id)
                    setSelectedId(environments.find(e => e.id !== selectedEnv.id)?.id || null)
                  }}
                  disabled={environments.length <= 1}
                >
                  <Trash2 className="size-4" />
                </Button>
              </div>

              <div className="flex-1 overflow-y-auto p-4">
                <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <h4 className="text-sm font-medium">Variables</h4>
                    <Button variant="outline" size="sm" onClick={handleAddVar} className="h-7 text-xs">
                      <Plus className="size-3 mr-1" /> Add Variable
                    </Button>
                  </div>

                  <div className="border rounded-md divide-y">
                    <div className="grid grid-cols-[auto_1fr_1fr_auto] gap-2 p-2 bg-muted/50 text-xs font-medium text-muted-foreground">
                      <div className="w-6" />
                      <div>VARIABLE</div>
                      <div>VALUE</div>
                      <div className="w-8" />
                    </div>
                    {selectedEnv.variables.length === 0 ? (
                      <div className="p-8 text-center text-sm text-muted-foreground">
                        No variables defined.
                      </div>
                    ) : (
                      selectedEnv.variables.map((v, i) => (
                        <div key={i} className="grid grid-cols-[auto_1fr_1fr_auto] gap-2 p-2 items-center group">
                          <div className="w-6 flex justify-center">
                            <Checkbox 
                              checked={v.enabled} 
                              onCheckedChange={(c) => updateVar(i, "enabled", !!c)}
                            />
                          </div>
                          <Input 
                            value={v.key} 
                            onChange={(e) => updateVar(i, "key", e.target.value)}
                            placeholder="KEY"
                            className="h-8 font-mono text-xs"
                          />
                          <Input 
                            value={v.value} 
                            onChange={(e) => updateVar(i, "value", e.target.value)}
                            placeholder="value"
                            className="h-8 font-mono text-xs"
                          />
                          <Button 
                            variant="ghost" 
                            size="icon" 
                            onClick={() => removeVar(i)}
                            className="size-8 opacity-0 group-hover:opacity-100 text-destructive"
                          >
                            <Trash2 className="size-3.5" />
                          </Button>
                        </div>
                      ))
                    )}
                  </div>
                </div>
              </div>
            </>
          ) : (
            <div className="flex-1 flex items-center justify-center text-muted-foreground">
              Select an environment
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useCallback, useRef, useState } from "react"
import { Upload, Download, FileJson, X, AlertTriangle, CheckCircle2, Loader2, Users } from "lucide-react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { useRequestStore, type Collection, type Environment, type VariableMapping } from "@/hooks/use-request-store"

/* ─────────────────────────────────────────────────────────────────────
   Types
───────────────────────────────────────────────────────────────────── */
interface ExportBundle {
  version: "1.0"
  exportedAt: string
  collections: Collection[]
  environments: Environment[]
  variableMappings: VariableMapping[]
}

type ConflictStrategy = "keep" | "overwrite" | "rename"

interface Conflict {
  type: "collection" | "environment"
  name: string
  existingId: string
  incomingId: string
}

/* ─────────────────────────────────────────────────────────────────────
   Export helpers
───────────────────────────────────────────────────────────────────── */
function buildBundle(collections: Collection[], environments: Environment[], variableMappings: VariableMapping[]): ExportBundle {
  return {
    version: "1.0",
    exportedAt: new Date().toISOString(),
    collections,
    environments,
    variableMappings,
  }
}

function downloadJson(data: object, filename: string) {
  const json = JSON.stringify(data, null, 2)
  const blob = new Blob([json], { type: "application/json" })
  const url = URL.createObjectURL(blob)
  const a = document.createElement("a")
  a.href = url
  a.download = filename
  document.body.appendChild(a)
  a.click()
  a.remove()
  URL.revokeObjectURL(url)
}

/* ─────────────────────────────────────────────────────────────────────
   Component
───────────────────────────────────────────────────────────────────── */
interface ImportExportModalProps {
  open: boolean
  onClose: () => void
}

export function ImportExportModal({ open, onClose }: ImportExportModalProps) {
  const { collections, environments, variableMappings, addCollection, addEnvironment, updateCollection, updateEnvironment, addRequestToCollection, addVariableMapping, updateVariableMapping } =
    useRequestStore()

  /* drag state */
  const [dragging, setDragging] = useState(false)
  const [importing, setImporting] = useState(false)
  const [importResult, setImportResult] = useState<{
    added: number
    updated: number
    skipped: number
    errors: string[]
  } | null>(null)
  const [conflicts, setConflicts] = useState<Conflict[]>([])
  const [pendingBundle, setPendingBundle] = useState<ExportBundle | null>(null)
  const [conflictStrategy, setConflictStrategy] = useState<ConflictStrategy>("rename")
  const fileInputRef = useRef<HTMLInputElement>(null)

  /* ── Export ──────────────────────────────────────────────────────── */
  const handleExport = () => {
    const bundle = buildBundle(collections, environments, variableMappings)
    const date = new Date().toISOString().slice(0, 10)
    downloadJson(bundle, `zendeeps-backup-${date}.json`)
  }

  /* ── Parse & detect conflicts ────────────────────────────────────── */
  const parseBundle = (raw: string): ExportBundle | null => {
    try {
      const parsed = JSON.parse(raw)
      if (!Array.isArray(parsed.collections) || !Array.isArray(parsed.environments)) return null
      return {
        version: parsed.version || "1.0",
        exportedAt: parsed.exportedAt || new Date().toISOString(),
        collections: parsed.collections,
        environments: parsed.environments,
        variableMappings: Array.isArray(parsed.variableMappings) ? parsed.variableMappings : [],
      }
    } catch {
      return null
    }
  }

  const detectConflicts = (bundle: ExportBundle): Conflict[] => {
    const found: Conflict[] = []
    bundle.collections.forEach((incoming) => {
      const existing = collections.find((c) => c.name === incoming.name || c.id === incoming.id)
      if (existing) found.push({ type: "collection", name: incoming.name, existingId: existing.id, incomingId: incoming.id })
    })
    bundle.environments.forEach((incoming) => {
      const existing = environments.find((e) => e.name === incoming.name || e.id === incoming.id)
      if (existing) found.push({ type: "environment", name: incoming.name, existingId: existing.id, incomingId: incoming.id })
    })
    return found
  }

  const areRequestsEquivalent = (a: any, b: any) =>
    a.name === b.name &&
    (a.url === b.url || a.endpoint === b.endpoint) &&
    a.method === b.method

  /* ── Apply import ────────────────────────────────────────────────── */
  const applyImport = useCallback(
    async (bundle: ExportBundle, strategy: ConflictStrategy) => {
      setImporting(true)
      let added = 0
      let updated = 0
      let skipped = 0
      const errors: string[] = []

      try {
        /* Collections */
        for (const incoming of bundle.collections) {
          const existing = collections.find((c) => c.name === incoming.name || c.id === incoming.id)
          if (!existing) {
            const { id, createdAt, updatedAt, ...rest } = incoming
            const newCollectionId = addCollection(rest)
            if (incoming.requests?.length) {
              incoming.requests.forEach((req) => addRequestToCollection(newCollectionId, req))
            }
            added++
          } else {
            if (strategy === "keep") {
              const newRequests = (incoming.requests || []).filter(
                (req) => !existing.requests.some((existingReq) => areRequestsEquivalent(existingReq, req))
              )
              if (newRequests.length) {
                newRequests.forEach((req) => addRequestToCollection(existing.id, req))
                updated++
              } else {
                skipped++
              }
            } else if (strategy === "overwrite") {
              updateCollection(existing.id, {
                requests: incoming.requests || [],
                description: incoming.description,
              })
              updated++
            } else {
              const { id, createdAt, updatedAt, ...rest } = incoming
              const duplicateName = `${incoming.name} (importé)`
              const newCollectionId = addCollection({ ...rest, name: duplicateName })
              if (incoming.requests?.length) {
                incoming.requests.forEach((req) => addRequestToCollection(newCollectionId, req))
              }
              added++
            }
          }
        }

        /* Environments */
        for (const incoming of bundle.environments) {
          if (incoming.name === "Global") {
            skipped++
            continue
          }
          const existing = environments.find((e) => e.name === incoming.name || e.id === incoming.id)
          if (!existing) {
            const { id, createdAt, updatedAt, ...rest } = incoming
            addEnvironment(rest)
            added++
          } else {
            if (strategy === "keep") {
              const newVars = (incoming.variables || []).filter(
                (variable) => !existing.variables.some((existingVar) => existingVar.key === variable.key)
              )
              if (newVars.length) {
                updateEnvironment(existing.id, {
                  variables: [...existing.variables, ...newVars],
                })
                updated++
              } else {
                skipped++
              }
            } else if (strategy === "overwrite") {
              updateEnvironment(existing.id, { variables: incoming.variables || [] })
              updated++
            } else {
              const { id, createdAt, updatedAt, ...rest } = incoming
              addEnvironment({ ...rest, name: `${incoming.name} (importé)` })
              added++
            }
          }
        }

        /* Variable mappings */
        for (const incoming of bundle.variableMappings || []) {
          const existing = variableMappings.find(
            (mapping) =>
              mapping.name === incoming.name &&
              mapping.sourceRequestId === incoming.sourceRequestId &&
              mapping.sourcePath === incoming.sourcePath
          )

          if (!existing) {
            addVariableMapping({
              name: incoming.name,
              sourceRequestId: incoming.sourceRequestId,
              sourcePath: incoming.sourcePath,
              enabled: incoming.enabled ?? true,
            })
            added++
          } else if (strategy === "overwrite") {
            updateVariableMapping(existing.id, {
              name: incoming.name,
              sourceRequestId: incoming.sourceRequestId,
              sourcePath: incoming.sourcePath,
              enabled: incoming.enabled ?? existing.enabled,
            })
            updated++
          } else {
            skipped++
          }
        }
      } catch (err) {
        errors.push(String(err))
      }

      setImportResult({ added, updated, skipped, errors })
      setConflicts([])
      setPendingBundle(null)
      setImporting(false)
    },
    [collections, environments, addCollection, addEnvironment, updateCollection, updateEnvironment, addRequestToCollection]
  )

  /* ── File processing ─────────────────────────────────────────────── */
  const processFile = useCallback(
    (file: File) => {
      const reader = new FileReader()
      reader.onload = (evt) => {
        const raw = evt.target?.result as string
        const bundle = parseBundle(raw)
        if (!bundle) {
          setImportResult({ added: 0, updated: 0, skipped: 0, errors: ["Fichier JSON invalide ou incompatible."] })
          return
        }
        const found = detectConflicts(bundle)
        if (found.length > 0) {
          setConflicts(found)
          setPendingBundle(bundle)
        } else {
          applyImport(bundle, conflictStrategy)
        }
      }
      reader.readAsText(file)
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [collections, environments, conflictStrategy, applyImport]
  )

  /* ── Drag & drop handlers ────────────────────────────────────────── */
  const onDragOver = (e: React.DragEvent) => { e.preventDefault(); setDragging(true) }
  const onDragLeave = () => setDragging(false)
  const onDrop = (e: React.DragEvent) => {
    e.preventDefault()
    setDragging(false)
    const file = e.dataTransfer.files[0]
    if (file) processFile(file)
  }

  const onFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file) processFile(file)
    e.target.value = ""
  }

  const reset = () => {
    setImportResult(null)
    setConflicts([])
    setPendingBundle(null)
    setDragging(false)
  }

  if (!open) return null

  return (
    <div
      className="fixed inset-0 z-[60] flex items-center justify-center p-4"
      role="dialog"
      aria-modal="true"
      aria-label="Import / Export"
    >
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black/50 backdrop-blur-sm"
        onClick={onClose}
      />

      {/* Panel */}
      <div className="relative z-10 w-full max-w-lg rounded-3xl border border-border bg-card shadow-2xl">
        {/* Header */}
        <div className="flex items-center justify-between border-b border-border px-6 py-5">
          <div className="flex items-center gap-3">
            <div className="flex size-9 items-center justify-center rounded-xl bg-primary/10">
              <Users className="size-5 text-primary" />
            </div>
            <div>
              <h2 className="text-base font-semibold text-foreground">Sync d'équipe</h2>
              <p className="text-xs text-muted-foreground">Import / Export de collections et environnements</p>
            </div>
          </div>
          <button
            id="import-export-modal-close"
            onClick={onClose}
            className="flex size-8 items-center justify-center rounded-xl text-muted-foreground hover:bg-accent hover:text-foreground transition-colors"
          >
            <X className="size-4" />
          </button>
        </div>

        <div className="space-y-5 px-6 py-5">
          {/* ── EXPORT section ───────────────────────────────────── */}
          <div className="rounded-2xl border border-border bg-background p-4">
            <div className="flex items-center justify-between gap-3">
              <div>
                <p className="text-sm font-medium text-foreground">Exporter mes données</p>
                <p className="mt-0.5 text-xs text-muted-foreground">
                  {collections.length} collection{collections.length !== 1 ? "s" : ""} ·{" "}
                  {environments.length} environnement{environments.length !== 1 ? "s" : ""}
                </p>
              </div>
              <Button
                id="export-bundle-btn"
                size="sm"
                onClick={handleExport}
