"use client"

import { useState } from "react"
import { Github, Loader2, X } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { toast } from "@/hooks/use-toast"
import type { SavedProject } from "@/types"

interface ImportGithubModalProps {
  open: boolean
  onClose: () => void
  onImport: (project: SavedProject) => void
}

export function ImportGithubModal({ open, onClose, onImport }: ImportGithubModalProps) {
  const [repoUrl, setRepoUrl] = useState("")
  const [isImporting, setIsImporting] = useState(false)
  const [importStatus, setImportStatus] = useState<string | null>(null)

  const parseGithubUrl = (url: string): { owner: string; repo: string; branch?: string } | null => {
    try {
      // Handle various GitHub URL formats
      const cleaned = url.replace(/^https:\/\/github\.com\//, "").replace(/\.git$/, "")
      const parts = cleaned.split("/")
      if (parts.length >= 2) {
        return {
          owner: parts[0],
          repo: parts[1],
          branch: parts[3] === "tree" ? parts[4] : undefined,
        }
      }
    } catch {
      // Ignore parse errors
    }
    return null
  }

  const handleImport = async () => {
    const parsed = parseGithubUrl(repoUrl)
    if (!parsed) {
      toast({ title: "URL GitHub invalide. Format: https://github.com/owner/repo", variant: "destructive" })
      return
    }

    setIsImporting(true)
    setImportStatus("Analyse du dépôt...")

    try {
      const response = await fetch(`/api/github-import`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          owner: parsed.owner,
          repo: parsed.repo,
          branch: parsed.branch,
        }),
      })

      if (!response.ok) {
        const error = await response.json().catch(() => ({}))
        throw new Error(error.message || "Erreur lors de l'import du dépôt")
      }

      const data = await response.json()
      setImportStatus("Détection des routes...")

      const project: SavedProject = {
        id: `proj-${Date.now()}`,
        name: data.name || `${parsed.owner}/${parsed.repo}`,
        framework: data.framework || "unknown",
        folderPath: `github:${parsed.owner}/${parsed.repo}`,
        port: data.port,
        routes: data.routes || [],
        analyzedAt: new Date().toISOString(),
        mode: "static",
      }

      onImport(project)
      toast({ title: `Projet "${project.name}" importé avec ${project.routes.length} routes`, meta: { event: "importExport" } } as any)
      onClose()
      setRepoUrl("")
    } catch (err) {
      toast({ title: err instanceof Error ? err.message : "Erreur lors de l'import", variant: "destructive", meta: { event: "importExport" } } as any)
    } finally {
      setIsImporting(false)
      setImportStatus(null)
    }
  }

  if (!open) return null

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/50" onClick={onClose} />
      <div className="relative z-10 w-full max-w-md rounded-xl border bg-card p-6 shadow-lg">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <Github className="size-5 text-primary" />
            <h2 className="text-lg font-semibold">Importer depuis GitHub</h2>
          </div>
          <button
            onClick={onClose}
            className="text-muted-foreground hover:text-foreground"
          >
            <X className="size-4" />
          </button>
        </div>

        <div className="space-y-4">
          <div>
            <label className="text-sm font-medium mb-1.5 block">
              URL du dépôt GitHub
            </label>
            <Input
              placeholder="https://github.com/owner/repo"
              value={repoUrl}
              onChange={(e) => setRepoUrl(e.target.value)}
              disabled={isImporting}
            />
            <p className="text-xs text-muted-foreground mt-1">
              Exemple: https://github.com/fastapi/full-stack-fastapi-postgresql
            </p>
          </div>

          {importStatus && (
            <div className="flex items-center gap-2 text-sm text-muted-foreground">
              <Loader2 className="size-4 animate-spin" />
              {importStatus}
            </div>
          )}

          <div className="flex gap-2">
            <Button
              variant="ghost"
              onClick={onClose}
              disabled={isImporting}
            >
              Annuler
            </Button>
            <Button
              onClick={handleImport}
              disabled={!repoUrl || isImporting}
            >
              {isImporting && <Loader2 className="size-4 mr-2 animate-spin" />}
              Importer
            </Button>
          </div>
        </div>
      </div>
    </div>
  )
}

"use client"

import { useState } from "react"
import { Loader2, FolderOpen, Sparkles, Code2, ChevronDown, Eye, EyeOff } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { cn, downloadJson } from "@/lib/utils"
import { isTauriAvailable } from "@/lib/tauri"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import type { AIProvider, AnalysisMode, SavedProject } from "@/hooks/use-projects-store"
import { loadApiKey, saveApiKey } from "@/hooks/use-projects-store"
import { analyzeProject } from '../lib/project-analyzer'
import { toast } from "@/hooks/use-toast"

const PROVIDERS: { value: AIProvider; label: string }[] = [
  { value: "anthropic", label: "Anthropic (Claude)" },
  { value: "openai", label: "OpenAI (GPT-4o)" },
  { value: "gemini", label: "Gemini 2.0 Flash" },
  { value: "ollama", label: "Ollama (local)" },
]

interface NewProjectModalProps {
  open: boolean
  onClose: () => void
  onAdd: (p: SavedProject) => void
}

export function NewProjectModal({ open, onClose, onAdd }: NewProjectModalProps) {
  const [mode, setMode] = useState<AnalysisMode>("static")
  const [provider, setProvider] = useState<AIProvider>("anthropic")
  const [apiKey, setApiKey] = useState(() => loadApiKey("anthropic"))
  const [showKey, setShowKey] = useState(false)
  const [folderPath, setFolderPath] = useState("")
  const [loading, setLoading] = useState(false)
  const [step, setStep] = useState("")

  const handleProviderChange = (p: AIProvider) => {
    setProvider(p)
    setApiKey(loadApiKey(p))
  }

  const pickFolder = async () => {
    if (isTauriAvailable()) {
      try {
        const { open } = await import("@tauri-apps/plugin-dialog")
        const selected = await open({ directory: true, multiple: false })
        if (selected && typeof selected === "string") {
          setFolderPath(selected)
        }
      } catch {
        toast({ title: "Impossible d'ouvrir le sélecteur de dossier", variant: "destructive" })
      }
    } else {
      downloadJson({ path: "" }, "dossier.json")
      toast({ title: "Mode navigateur : téléchargement d'un modèle JSON. Sous Tauri, le sélecteur de dossier natif sera disponible.", meta: { event: "projectImport" } } as any)
    }
  }

  const analyze = async () => {
    if (!folderPath) { toast({ title: "Sélectionnez un dossier", variant: "destructive" }); return }
    if (mode === "ai" && provider !== "ollama" && !apiKey.trim()) {
      toast({ title: "Clé API requise", variant: "destructive" }); return
    }
    if (mode === "ai" && provider !== "ollama") saveApiKey(provider, apiKey)
    setLoading(true)
    try {
      setStep("Analyse en cours…")
      const result = await analyzeProject(folderPath, mode, provider, mode === "ai" ? apiKey : undefined)

      const project: SavedProject = {
        id: `proj-${Date.now()}`,
        name: result.name,
        framework: result.framework,
        folderPath,
        port: result.port,
        routes: result.routes,
        analyzedAt: new Date().toISOString(),
        mode,
      }
      onAdd(project)
      toast({ title: `${result.routes.length} routes détectées`, meta: { event: "projectAdd" } } as any)
      onClose()
      setFolderPath("")
    } catch (err) {
      toast({ title: `Erreur : ${String(err)}`, variant: "destructive", meta: { event: "projectAdd" } } as any)
    } finally {
      setLoading(false)
      setStep("")
    }
  }

  return (
    <Dialog open={open} onOpenChange={(o) => !o && onClose()}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FolderOpen className="size-5 text-primary" /> Nouveau projet
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4 pt-2">
          {/* Mode toggle */}
          <div className="flex rounded-lg border border-border overflow-hidden">
            <button
              onClick={() => setMode("static")}
              className={cn("flex-1 flex items-center justify-center gap-2 py-2 text-sm font-medium transition-colors",
                mode === "static" ? "bg-primary text-primary-foreground" : "text-muted-foreground hover:bg-accent")}
            >
              <Code2 className="size-4" /> Parser statique
            </button>
            <button
              onClick={() => setMode("ai")}
              className={cn("flex-1 flex items-center justify-center gap-2 py-2 text-sm font-medium transition-colors",
                mode === "ai" ? "bg-primary text-primary-foreground" : "text-muted-foreground hover:bg-accent")}
            >
              <Sparkles className="size-4" /> Analyse IA
            </button>
          </div>

          {/* AI options */}
          {mode === "ai" && (
            <div className="space-y-3 rounded-lg border border-border bg-muted/30 p-3">
              <div className="relative">
                <select
                  value={provider}
                  onChange={(e) => handleProviderChange(e.target.value as AIProvider)}
                  className="w-full appearance-none rounded-md border border-border bg-background px-3 py-2 pr-8 text-sm focus:outline-none focus:ring-2 focus:ring-primary"
                >
                  {PROVIDERS.map((p) => (
                    <option key={p.value} value={p.value}>{p.label}</option>
                  ))}
                </select>
                <ChevronDown className="pointer-events-none absolute right-2.5 top-1/2 size-4 -translate-y-1/2 text-muted-foreground" />
              </div>
              {provider !== "ollama" && (
                <div className="relative">
                  <Input
                    type={showKey ? "text" : "password"}
                    placeholder="Clé API…"
                    value={apiKey}
                    onChange={(e) => setApiKey(e.target.value)}
                    className="pr-9 text-sm"
                  />
                  <button
                    type="button"
                    onClick={() => setShowKey((v) => !v)}
                    className="absolute right-2.5 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                  >
                    {showKey ? <EyeOff className="size-4" /> : <Eye className="size-4" />}
                  </button>
                </div>
              )}
            </div>
          )}

          {/* Folder picker */}
          <div className="flex gap-2">
            <Input
              value={folderPath}
              readOnly
              placeholder="Chemin du dossier…"
              className="flex-1 text-sm"
            />
            <Button variant="outline" size="sm" onClick={pickFolder} className="shrink-0 gap-1.5">
              <FolderOpen className="size-4" /> Parcourir
            </Button>
          </div>

          <Button
            className="w-full gap-2"
            onClick={analyze}
            disabled={loading || !folderPath}
          >
            {loading ? (
              <><Loader2 className="size-4 animate-spin" /> {step || "Analyse…"}</>
            ) : (
              <><Sparkles className="size-4" /> Analyser</>
            )}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  )
}

