import { createContext, useContext, useState, useEffect, type ReactNode } from "react"
import { useIsMobile } from "@/hooks/use-mobile"

interface SidebarContextType {
  isCollapsed: boolean
  toggleSidebar: () => void
  collapseSidebar: () => void
  expandSidebar: () => void
}

const SidebarContext = createContext<SidebarContextType | undefined>(undefined)

export function SidebarProvider({ children }: { children: ReactNode }) {
  const [isCollapsed, setIsCollapsed] = useState(false)

  const isNarrow = useIsMobile(916)

  // Load from localStorage
  useEffect(() => {
    const stored = localStorage.getItem("sidebar-collapsed")
    if (stored) {
      setIsCollapsed(JSON.parse(stored))
    }
  }, [])

  // Close sidebar automatically on narrower desktop widths
  useEffect(() => {
    if (isNarrow) {
      setIsCollapsed(true)
    }
  }, [isNarrow])

  // Save to localStorage
  useEffect(() => {
    localStorage.setItem("sidebar-collapsed", JSON.stringify(isCollapsed))
  }, [isCollapsed])

  const toggleSidebar = () => setIsCollapsed((prev) => !prev)
  const collapseSidebar = () => setIsCollapsed(true)
  const expandSidebar = () => setIsCollapsed(false)

  return (
    <SidebarContext.Provider value={{ isCollapsed, toggleSidebar, collapseSidebar, expandSidebar }}>
      {children}
    </SidebarContext.Provider>
  )
}

export function useSidebar() {
  const context = useContext(SidebarContext)
  if (!context) {
    throw new Error("useSidebar must be used within a SidebarProvider")
  }
  return context
}

import * as React from 'react'

const MOBILE_BREAKPOINT = 768

export function useIsMobile(maxWidth = MOBILE_BREAKPOINT) {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mediaQuery = window.matchMedia(`(max-width: ${maxWidth}px)`)
    const onChange = () => {
      setIsMobile(mediaQuery.matches)
    }
    mediaQuery.addEventListener('change', onChange)
    setIsMobile(mediaQuery.matches)
    return () => mediaQuery.removeEventListener('change', onChange)
  }, [maxWidth])

  return !!isMobile
}

