}

const STORAGE_KEY = "zendeeps-request-store"
const STORE_UPDATE_EVENT = "zendeeps-store-update"

const defaultEnvironments: Environment[] = [
  {
    id: "env-global",
    name: "Global",
    color: "slate",
    variables: [],
    createdAt: Date.now(),
    updatedAt: Date.now(),
  },
]

const initialStore: RequestStore = {
  history: [],
  collections: [],
  environments: defaultEnvironments,
  notifications: [],
  variableMappings: [],
  systemNotificationPermission: typeof window !== 'undefined' && 'Notification' in window ? Notification.permission : 'default',
  activeEnvironmentId: "env-global",
  projects: [],
  selectedProjectId: null,
}

function loadFromStorage(): RequestStore {
  try {
    const stored = localStorage.getItem(STORAGE_KEY)
    if (!stored) return loadFallback()
    const parsed = JSON.parse(stored)
    return {
      history: parsed.history || [],
      collections: parsed.collections || [],
      environments: parsed.environments || defaultEnvironments,
      notifications: parsed.notifications || [],
      variableMappings: parsed.variableMappings || [],
      systemNotificationPermission:
        parsed.systemNotificationPermission ?? (typeof window !== 'undefined' && 'Notification' in window ? Notification.permission : 'unsupported'),
      activeEnvironmentId:
        parsed.activeEnvironmentId !== undefined
          ? parsed.activeEnvironmentId
          : "env-global",
      projects: parsed.projects || [],
      selectedProjectId: parsed.selectedProjectId ?? null,
    }
  } catch {
    return loadFallback()
  }
}

/** Fallback : si la clé principale n'existe pas, on tente la migration depuis l'ancienne clé */
function loadFallback(): RequestStore {
  try {
    const legacy = localStorage.getItem("probe_projects")
    const fallbackProjects: SavedProject[] = legacy ? JSON.parse(legacy) : []
    return {
      history: [],
      collections: [],
      environments: defaultEnvironments,
      notifications: [],
      systemNotificationPermission: typeof window !== 'undefined' && 'Notification' in window ? Notification.permission : 'unsupported',
      variableMappings: [],
      activeEnvironmentId: "env-global",
      projects: fallbackProjects,
      selectedProjectId: null,
    }
  } catch {
    return {
      history: [],
      collections: [],
      environments: defaultEnvironments,
      notifications: [],
      systemNotificationPermission: typeof window !== 'undefined' && 'Notification' in window ? Notification.permission : 'unsupported',
      variableMappings: [],
      activeEnvironmentId: "env-global",
      projects: [],
      selectedProjectId: null,
    }
  }
}

function saveToStorage(store: RequestStore) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(store))
  } catch {}
}

/* ─────────────────────────────────────────────────────────────────────────
   Proactive notifications — runs once on app load
   Rules:
   1. Any endpoint whose avg response time is ≥130% of its own historical baseline
   2. Any endpoint with error rate > 20% over last 10 calls
   3. Any collection not used (no requests) for more than 7 days
───────────────────────────────────────────────────────────────────────── */
function runProactiveAnalysis(store: RequestStore) {
  try {
    const { history, collections } = store
    if (!history.length) return

    const NOW = Date.now()
    const SEVEN_DAYS_MS = 7 * 24 * 60 * 60 * 1000
    const ERROR_THRESHOLD = 0.2   // 20 %
    const SLOW_THRESHOLD  = 1.3   // +30 %

    /* ── 1. Group history by endpoint ─────────────────────────── */
    const endpointMap = new Map<
      string,
      { times: number[]; statuses: number[]; lastUsed: number }
    >()

    for (const item of history) {
      const key = item.endpoint || item.url || "Unknown"
      if (!endpointMap.has(key)) {
        endpointMap.set(key, { times: [], statuses: [], lastUsed: 0 })
      }
      const bucket = endpointMap.get(key)!
      if (item.responseTime != null) bucket.times.push(item.responseTime)
      if (item.responseStatus != null) bucket.statuses.push(item.responseStatus)
      if (item.executedAt > bucket.lastUsed) bucket.lastUsed = item.executedAt
    }

    /* ── 2. Slow endpoint detection ───────────────────────────── */
    for (const [endpoint, data] of endpointMap.entries()) {
      if (data.times.length < 3) continue   // need enough samples

      const allAvg = data.times.reduce((s, t) => s + t, 0) / data.times.length
      // Compare last 3 calls to overall average
      const recent3 = data.times.slice(-3)
      const recentAvg = recent3.reduce((s, t) => s + t, 0) / recent3.length

      if (recentAvg >= allAvg * SLOW_THRESHOLD) {
        toast({
          title: `⚠️ Endpoint lent détecté`,
          description: `${endpoint} répond ~${Math.round(recentAvg)}ms en moyenne (normale : ~${Math.round(allAvg)}ms, soit +${Math.round((recentAvg / allAvg - 1) * 100)}%).`,
          variant: "default",
        })
      }
    }

    /* ── 3. High error rate detection (last 10 calls) ─────────── */
    for (const [endpoint, data] of endpointMap.entries()) {
      const last10 = data.statuses.slice(-10)
      if (last10.length < 3) continue

      const errorCount = last10.filter((s) => s >= 400).length
      const errorRate = errorCount / last10.length

      if (errorRate > ERROR_THRESHOLD) {
        toast({
          title: `🔴 Taux d'erreur élevé`,
          description: `${endpoint} a ${Math.round(errorRate * 100)}% d'erreurs sur les ${last10.length} derniers appels.`,
          variant: "destructive",
        })
      }
    }

    /* ── 4. Stale collections (unused > 7 days) ───────────────── */
    for (const collection of collections) {
      if (!collection.requests.length) continue

      // Find the most recent usage of any request in this collection
      let lastUsed = collection.updatedAt
      for (const request of collection.requests) {
        const matchedRequests = history.filter(
          (item) => item.endpoint === request.endpoint || item.url === request.url
        )
        if (matchedRequests.length) {
          const latest = Math.max(...matchedRequests.map((item) => item.executedAt))
          lastUsed = Math.max(lastUsed, latest)
        }
      }

      if (NOW - lastUsed > SEVEN_DAYS_MS) {
        const daysAgo = Math.floor((NOW - lastUsed) / (24 * 60 * 60 * 1000))
        toast({
          title: `📁 Collection inactive`,
          description: `"${collection.name}" n'a pas été utilisée depuis ${daysAgo} jours.`,
          variant: "default",
        })
      }
    }
  } catch {
    // Never crash the app on analytics errors
  }
}

export function useRequestStore() {
  const [store, setStore] = useState<RequestStore>(initialStore)
  const [isLoaded, setIsLoaded] = useState(false)
  // Keep a ref always in sync so mutations can read latest state synchronously
  const storeRef = useRef<RequestStore>(initialStore)

  // Load from localStorage on mount
  useEffect(() => {
    const loaded = loadFromStorage()
    storeRef.current = loaded
    setStore(loaded)
    setIsLoaded(true)

    // ── Proactive notifications analysis ──────────────────────────
    runProactiveAnalysis(loaded)

    const handleUpdate = () => {
      const latest = loadFromStorage()
      storeRef.current = latest
      setStore(latest)
    }

    window.addEventListener(STORE_UPDATE_EVENT, handleUpdate)

    const handleStorage = (event: StorageEvent) => {
      if (event.key === STORAGE_KEY || event.key === null) {
        const latest = loadFromStorage()
        storeRef.current = latest
        setStore(latest)
      }
    }

    window.addEventListener("storage", handleStorage)
    return () => {
      window.removeEventListener(STORE_UPDATE_EVENT, handleUpdate)
      window.removeEventListener("storage", handleStorage)
    }
  }, [])

  // Helper: apply an update, save synchronously, and schedule a React re-render
  const commit = useCallback((updater: (prev: RequestStore) => RequestStore) => {
    const next = updater(storeRef.current)
    try {
      console.log('STORE COMMIT: next.collections.length=', next.collections.length)
    } catch {}
    storeRef.current = next
    saveToStorage(next)   // ← synchronous write, survives immediate navigation
    setStore(next)        // ← triggers re-render
    window.dispatchEvent(new Event(STORE_UPDATE_EVENT)) // ← sync other components
  }, [])

  // ── Notifications ───────────────────────────────────────────────────────
  const addNotification = useCallback(
    (notif: Omit<Notification, "id" | "createdAt" | "read">) => {
      const newNotif: Notification = {
        ...notif,
        id: `notif-${Date.now()}`,
        read: false,
        createdAt: Date.now(),
      }
      commit((prev) => ({ ...prev, notifications: [newNotif, ...prev.notifications] }))
      // Show an in-app toast panel for every notification event (gated by settings).
      try {
        toast({
          title: newNotif.title,
          description: newNotif.body,
          variant: newNotif.type === "error" ? "destructive" : "default",
          meta: { event: newNotif.event },
        } as any)
      } catch {}
      // Show system notification when permission granted (check stored permission)
      try {
        const perm = storeRef.current.systemNotificationPermission ?? (typeof window !== "undefined" && "Notification" in window ? Notification.permission : undefined)
        if (perm === "granted" && typeof window !== "undefined" && "Notification" in window) {
          try {
            new Notification(newNotif.title, { body: newNotif.body })
          } catch {}
        }
      } catch {}
      return newNotif.id
    },
    [commit]
  )

  const requestSystemNotificationPermission = useCallback(async () => {
    if (typeof window === "undefined" || !("Notification" in window)) return "unsupported"
    try {
      const result = await Notification.requestPermission()
      commit((prev) => ({ ...prev, systemNotificationPermission: result }))
      return result // 'granted' | 'denied' | 'default'
    } catch {
      commit((prev) => ({ ...prev, systemNotificationPermission: "default" }))
      return "default"
    }
  }, [])

  const markNotificationRead = useCallback(
    (id: string) => {
      commit((prev) => ({
        ...prev,
        notifications: prev.notifications.map((n) => (n.id === id ? { ...n, read: true } : n)),
      }))
    },
    [commit]
  )

  const clearNotifications = useCallback(() => {
    commit((prev) => ({ ...prev, notifications: [] }))
  }, [commit])

  // ── History ───────────────────────────────────────────────────────────────

  const addToHistory = useCallback(
    (item: Omit<HistoryItem, "id" | "executedAt" | "createdAt" | "updatedAt">) => {
      commit((prev) => ({
        ...prev,
        history: [
          {
            ...item,
            id: `hist-${Date.now()}`,
            createdAt: Date.now(),
            updatedAt: Date.now(),
            executedAt: Date.now(),
          },
          ...prev.history,
        ].slice(0, 100),
      }))
      runProactiveAnalysis(storeRef.current)
    },
    [commit]
  )

  // When a request is executed, add a simple notification
  const _addHistoryAndNotify = useCallback(
    (item: Omit<HistoryItem, "id" | "executedAt" | "createdAt" | "updatedAt">) => {
      addToHistory(item)
      try {
        addNotification({
            title: `Requête ${item.method} ${item.endpoint}`,
            body: `Statut: ${item.responseStatus ?? "-"} — ${item.responseTime ?? "-"}ms`,
            type: "info",
            event: "requestComplete",
        })
      } catch {}
    },
    [addToHistory, addNotification]
  )

  const clearHistory = useCallback(() => {
    commit((prev) => ({ ...prev, history: [] }))
  }, [commit])

  const removeFromHistory = useCallback(
    (id: string) => {
      commit((prev) => ({
        ...prev,
        history: prev.history.filter((h) => h.id !== id),
      }))
    },
    [commit]
  )

  // ── Collections ───────────────────────────────────────────────────────────

  const addCollection = useCallback(
    (collection: Omit<Collection, "id" | "createdAt" | "updatedAt" | "requests">) => {
      const newCollection: Collection = {
        ...collection,
        id: `col-${Date.now()}`,
        requests: [],
        createdAt: Date.now(),
        updatedAt: Date.now(),
      }
      commit((prev) => ({
        ...prev,
        collections: [...prev.collections, newCollection],
      }))
      try {
        console.log('STORE ACTION: addCollection -> added', newCollection.id, newCollection.name)
      } catch {}
      try {
        addNotification({
          title: `Collection créée: ${collection.name}`,
          body: `La collection "${collection.name}" a été créée.`,
          type: "success",
          event: "collectionComplete",
        })
      } catch {}
      return newCollection.id
    },
    [commit]
  )

  const updateCollection = useCallback(
    (id: string, updates: Partial<Collection>) => {
      commit((prev) => ({
        ...prev,
        collections: prev.collections.map((c) =>
          c.id === id ? { ...c, ...updates, updatedAt: Date.now() } : c
        ),
      }))
    },
    [commit]
  )

  const deleteCollection = useCallback(
    (id: string) => {
      commit((prev) => ({
        ...prev,
        collections: prev.collections.filter((c) => c.id !== id),
      }))
    },
    [commit]
  )

  const addRequestToCollection = useCallback(
    (
      collectionId: string,
      request: Omit<RequestItem, "id" | "createdAt" | "updatedAt">
    ) => {
      const newRequest: RequestItem = {
        ...request,
        id: `req-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`,
        createdAt: Date.now(),
        updatedAt: Date.now(),
      }
      commit((prev) => ({
        ...prev,
        collections: prev.collections.map((c) =>
          c.id === collectionId
            ? { ...c, requests: [...c.requests, newRequest], updatedAt: Date.now() }
            : c
        ),
      }))
      try {
        console.log('STORE ACTION: addRequestToCollection ->', collectionId, newRequest.id)
      } catch {}
      return newRequest.id
    },
    [commit]
  )

  const removeRequestFromCollection = useCallback(
    (collectionId: string, requestId: string) => {
      commit((prev) => ({
        ...prev,
        collections: prev.collections.map((c) =>
          c.id === collectionId
            ? {
                ...c,
                requests: c.requests.filter((r) => r.id !== requestId),
                updatedAt: Date.now(),
              }
            : c
        ),
      }))
    },
    [commit]
  )

  const updateRequestInCollection = useCallback(
    (collectionId: string, requestId: string, updates: Partial<RequestItem>) => {
      commit((prev) => ({
        ...prev,
        collections: prev.collections.map((c) =>
          c.id === collectionId
            ? {
                ...c,
                requests: c.requests.map((r) =>
                  r.id === requestId ? { ...r, ...updates, updatedAt: Date.now() } : r
                ),
                updatedAt: Date.now(),
              }
            : c
        ),
      }))
    },
    [commit]
  )

  const updateRequestById = useCallback(
    (requestId: string, updates: Partial<RequestItem>) => {
      commit((prev) => ({
        ...prev,
        collections: prev.collections.map((c) => {
          const hasUpdatedRequest = c.requests.some((r) => r.id === requestId)
          return {
            ...c,
            requests: c.requests.map((r) =>
              r.id === requestId ? { ...r, ...updates, updatedAt: Date.now() } : r
            ),
            updatedAt: hasUpdatedRequest ? Date.now() : c.updatedAt,
          }
        }),
      }))
    },
    [commit]
  )

  const addVariableMapping = useCallback(
    (mapping: Omit<VariableMapping, "id" | "createdAt" | "updatedAt">) => {
      const newMapping: VariableMapping = {
        ...mapping,
        id: `map-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`,
        createdAt: Date.now(),
        updatedAt: Date.now(),
      }
      commit((prev) => ({
        ...prev,
        variableMappings: [...prev.variableMappings, newMapping],
      }))
      return newMapping.id
    },
    [commit]
  )

  const updateVariableMapping = useCallback(
    (mappingId: string, updates: Partial<VariableMapping>) => {
      commit((prev) => ({
        ...prev,
        variableMappings: prev.variableMappings.map((mapping) =>
          mapping.id === mappingId ? { ...mapping, ...updates, updatedAt: Date.now() } : mapping
        ),
      }))
    },
    [commit]
  )

  const removeVariableMapping = useCallback(
    (mappingId: string) => {
      commit((prev) => ({
        ...prev,
        variableMappings: prev.variableMappings.filter((mapping) => mapping.id !== mappingId),
      }))
    },
    [commit]
  )

  // ── Projects ────────────────────────────────────────────────────────────

  const addProject = useCallback(
    (project: Omit<SavedProject, "id">) => {
      commit((prev) => ({
        ...prev,
        projects: [
          {
            ...project,
            id: `proj-${Date.now()}`,
          },
          ...prev.projects,
        ],
      }))
    },
    [commit]
  )

  const deleteProject = useCallback(
    (projectId: string) => {
      commit((prev) => ({
        ...prev,
        projects: prev.projects.filter((p) => p.id !== projectId),
      }))
    },
    [commit]
  )

  const updateProject = useCallback(
    (projectId: string, updates: Partial<SavedProject>) => {
      commit((prev) => ({
        ...prev,
        projects: prev.projects.map((p) =>
          p.id === projectId ? { ...p, ...updates } : p
        ),
      }))
    },
    [commit]
  )

  const setSelectedProject = useCallback(
    (projectId: string | null) => {
      commit((prev) => ({ ...prev, selectedProjectId: projectId }))
    },
    [commit]
  )

  // ── Environments ──────────────────────────────────────────────────────────

  const addEnvironment = useCallback(
    (env: Omit<Environment, "id" | "createdAt" | "updatedAt">) => {
      const newEnv: Environment = {
        ...env,
        id: `env-${Date.now()}`,
        createdAt: Date.now(),
        updatedAt: Date.now(),
      }
      commit((prev) => ({
        ...prev,
        environments: [...prev.environments, newEnv],
      }))
      return newEnv.id
    },
    [commit]
  )

  const updateEnvironment = useCallback(
    (id: string, updates: Partial<Environment>) => {
      commit((prev) => ({
        ...prev,
        environments: prev.environments.map((e) =>
          e.id === id ? { ...e, ...updates, updatedAt: Date.now() } : e
        ),
      }))
    },
    [commit]
  )

  const deleteEnvironment = useCallback(
    (id: string) => {
      commit((prev) => ({
        ...prev,
        environments: prev.environments.filter((e) => e.id !== id),
        activeEnvironmentId:
          prev.activeEnvironmentId === id ? null : prev.activeEnvironmentId,
      }))
    },
    [commit]
  )

  const setActiveEnvironment = useCallback(
    (id: string | null) => {
      commit((prev) => ({ ...prev, activeEnvironmentId: id }))
    },
    [commit]
  )

  return {
    history: store.history,
    collections: store.collections,
    environments: store.environments,
    activeEnvironmentId: store.activeEnvironmentId,
    projects: store.projects,
    selectedProjectId: store.selectedProjectId,
    isLoaded,
    addToHistory,
    clearHistory,
    removeFromHistory,
    addCollection,
    updateCollection,
    deleteCollection,
    addRequestToCollection,
    removeRequestFromCollection,
    updateRequestInCollection,
    updateRequestById,
    addProject,
    updateProject,
    deleteProject,
    setSelectedProject,
    addEnvironment,
    updateEnvironment,
    deleteEnvironment,
    setActiveEnvironment,
    notifications: store.notifications,
    addNotification,
    markNotificationRead,
    clearNotifications,
    variableMappings: store.variableMappings,
    addVariableMapping,
    updateVariableMapping,
    removeVariableMapping,
    addHistoryAndNotify: _addHistoryAndNotify,
    requestSystemNotificationPermission,
    systemNotificationPermission: store.systemNotificationPermission,
  }
}

'use client'

// Inspired by react-hot-toast library
import * as React from 'react'

import type { ToastActionElement, ToastProps } from '@/components/ui/toast'

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 6000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  meta?: Record<string, any>
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: 'ADD_TOAST',
  UPDATE_TOAST: 'UPDATE_TOAST',
  DISMISS_TOAST: 'DISMISS_TOAST',
  REMOVE_TOAST: 'REMOVE_TOAST',
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType['ADD_TOAST']
      toast: ToasterToast
    }
  | {
      type: ActionType['UPDATE_TOAST']
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType['DISMISS_TOAST']
      toastId?: ToasterToast['id']
    }
  | {
      type: ActionType['REMOVE_TOAST']
      toastId?: ToasterToast['id']
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: 'REMOVE_TOAST',
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case 'ADD_TOAST':
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case 'UPDATE_TOAST':
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t,
        ),
      }

    case 'DISMISS_TOAST': {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t,
        ),
      }
    }
    case 'REMOVE_TOAST':
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, 'id'>

function toast({ ...props }: Toast & { meta?: Record<string, any> }) {
  try {
    const pushEnabled = typeof window !== 'undefined' && localStorage.getItem('probe_push_enabled') === 'true'
    const event = (props as any).meta?.event

    // Always allow collection-created toasts regardless of global push setting
    const isCollectionEvent = event === 'collectionComplete'

    if (!pushEnabled && !isCollectionEvent) {
      return {
        id: '',
        dismiss: () => {},
        update: () => {},
      }
    }

    if (event && typeof window !== 'undefined') {
      try {
        const eventsRaw = localStorage.getItem('probe_push_events') || '{}'
        const events = JSON.parse(eventsRaw)
        if (events && events[event] === false) {
          return {
            id: '',
            dismiss: () => {},
            update: () => {},
          }
        }
      } catch {}
    }
  } catch {}
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: 'UPDATE_TOAST',
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: 'DISMISS_TOAST', toastId: id })

  dispatch({
    type: 'ADD_TOAST',
    toast: {
      ...props,
      id,
      open: true,
      duration: props.duration ?? 4000,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: 'DISMISS_TOAST', toastId }),
  }
}

export { useToast, toast }

"use client"

import path from "path"
import type { AIProvider, DetectedRoute, SavedProject, AnalysisMode } from "@/hooks/use-projects-store"
import { loadOllamaConfig } from "@/hooks/use-projects-store"
import { readDir, readTextFile } from "@tauri-apps/plugin-fs"

const FRAMEWORK_FILE_EXTENSIONS: Record<string, string[]> = {
  fastapi: [".py"],
  express: [".js", ".ts", ".jsx", ".tsx"],
  nestjs: [".js", ".ts"],
  laravel: [".php"],
}

function isRelevantFile(filePath: string, framework: string): boolean {
  if (framework === "unknown") return true
  const exts = FRAMEWORK_FILE_EXTENSIONS[framework]
  if (!exts) return true
  return exts.includes(path.extname(filePath).toLowerCase())
}

// ── Constants ─────────────────────────────────────────────────────────────

const IGNORED_FOLDERS = [
  "node_modules", ".git", ".next", "dist", "build",
  "__pycache__", ".venv", "venv", "env", "vendor",
]
const MAX_FILES = 150

// ── Public API ───────────────────────────────────────────────────────────

export async function analyzeProject(
  folderPath: string,
  mode: AnalysisMode,
  provider?: AIProvider,
  apiKey?: string,
): Promise<SavedProject> {
  if (mode === "ai") {
    if (provider !== "ollama" && !apiKey) throw new Error("Clé API requise pour l'analyse IA")
    return analyzeWithAI(folderPath, provider ?? "openai", apiKey)
  }
  return analyzeStatic(folderPath)
}

// ── Static analysis ──────────────────────────────────────────────────────

async function analyzeStatic(folderPath: string): Promise<SavedProject> {
  const filePaths = await getFiles(folderPath)
  const files: { path: string; content: string }[] = []
  const routes: DetectedRoute[] = []

  // Read each file content
  for (const fp of filePaths) {
    try {
      const content = await readTextFile(fp)
      files.push({ path: fp, content })
    } catch { /* skip unreadable file */ }
  }

  // Detect framework before route detection (framework-first strategy)
  const framework = detectFramework(files)
  // Keep only files relevant to the detected framework to avoid noisy matches
  const relevantFiles = files.filter((f) => isRelevantFile(f.path, framework))

  // Extract include_router prefixes so we can apply them to router files
  const prefixMap: Record<string, string> = {}
  const INCLUDE_ROUTER_RE = /include_router\s*\(\s*([A-Za-z0-9_.]+)\s*,\s*prefix\s*:\s*['\"]([^'\"]+)['\"]|include_router\s*\(\s*([A-Za-z0-9_.]+)\s*,\s*prefix\s*=\s*['\"]([^'\"]+)['\"]/g
  for (const f of relevantFiles) {
    let m
    INCLUDE_ROUTER_RE.lastIndex = 0
    while ((m = INCLUDE_ROUTER_RE.exec(f.content)) !== null) {
      const ident = (m[1] || m[3] || "").split('.')[0]
      const pref = (m[2] || m[4] || "")
      if (ident && pref) prefixMap[ident] = pref
    }
  }

  // Detect routes per framework and deduplicate globally (method|path)
  const seen = new Set<string>()
  for (const f of relevantFiles) {
    const detected = detectRoutes(f.content, f.path, framework)
    // Try to find a prefix for this file (by identifier matching filename)
    const filename = f.path.split(/[\\/]/).pop() || f.path
    const base = filename.replace(/\.[^.]+$/, "")
    const prefix = prefixMap[base]

    for (const r of detected) {
      // apply prefix if available
      if (prefix) {
        const p = `${prefix}/${r.path}`.replace(/\/+/g, '/')
        r.path = normalizePath(p)
      }
      const key = `${r.method}|${r.path}`
      if (seen.has(key)) continue
      seen.add(key)
      r.sourceFile = f.path
      routes.push(r)
    }
  }

  return {
    id: `proj-${Date.now()}`,
    name: deriveName(folderPath),
    framework,
    folderPath,
    port: detectPort(files) ?? defaultPortForFramework(framework),
    routes,
    analyzedAt: new Date().toISOString(),
    mode: "static",
  }
}

function defaultPortForFramework(framework: string): number | undefined {
  switch (framework) {
    case "fastapi": return 8000
    case "express": return 3000
    case "nestjs": return 3000
    case "laravel": return 8000
    default: return undefined
  }
}

/** Recursive walk: returns all native OS file paths under `folderPath`. */
async function getFiles(folderPath: string, depth = 0): Promise<string[]> {
  if (depth > 8) return []
  const results: string[] = []

  try {
    const entries = await readDir(folderPath)
    for (const entry of entries) {
      if (results.length >= MAX_FILES) break
      if (shouldSkip(entry.name)) continue
      if (entry.isDirectory) {
        const childPath = `${folderPath}/${entry.name}`
        results.push(...(await getFiles(childPath, depth + 1)))
      } else if (entry.isFile) {
        results.push(`${folderPath}/${entry.name}`)
      }
      if (results.length >= MAX_FILES) break
    }
  } catch { /* skip unreadable folder */ }

  return results
}

function shouldSkip(name: string): boolean {
  return IGNORED_FOLDERS.includes(name) || name.startsWith(".")
}

function deriveName(folderPath: string): string {
  return folderPath.split(/[/\\]/).filter(Boolean).pop() ?? "Projet"
}

// ── Port detection ─────────────────────────────────────────────────────────

const PORT_PATTERNS: RegExp[] = [
  // app.listen(3001, ...) or app.listen(3001)
  /\.listen\(\s*(\d+)(?:\s*,|\s*\))/,
  // app.listen(process.env.PORT || 3001, ...)
  /\.listen\(\s*process\.env\.PORT\s*\|\|\s*(\d+)(?:\s*,|\s*\))/,
  // const PORT = process.env.PORT || 3001;
  /process\.env\.PORT\s*\|\|\s*(\d+)/,
  // uvicorn.run(..., port=8000) for FastAPI/uvicorn
  /uvicorn\.run\([\s\S]*?port\s*[:=]\s*(\d+)/,
]

function detectPort(files: { path: string; content: string }[]): number | undefined {
  const all = files.map((f) => f.content).join("\n")
  for (const p of PORT_PATTERNS) {
    p.lastIndex = 0
    const m = p.exec(all)
    if (m) return parseInt(m[1], 10)
  }
  return undefined
}

// ── Framework detection ───────────────────────────────────────────────────

interface FileInfo {
  path: string
  content: string
}

function detectFramework(files: FileInfo[]): string {
  if (files.length === 0) return "unknown"
  const all = files.map((f) => f.content).join("\n")

  // Node.js / Express — strongest signal first
  if (/require\s*\(\s*['"]express['"]\s*\)/.test(all)) return "express"
  if (/express\s*\(\s*\)/.test(all))                       return "express"

  // Python / FastAPI
  if (/from\s+fastapi\s+import/.test(all)) return "fastapi"
  if (/FastAPI\s*\(/.test(all))             return "fastapi"

  // NestJS
  if (/@nestjs/.test(all)    ) return "nestjs"
  if (/@Controller/.test(all)) return "nestjs"

  // Laravel / Symfony
  if (/Route::/.test(all))             return "laravel"
  if (/@return\s+Response/.test(all))  return "laravel"

  return "unknown"
}

// ── Route detection per framework ─────────────────────────────────────────

// --- Express / Node.js -----------------------------------------------------

const EXPRESS_PATTERNS: RegExp[] = [
  // app.get('/path', ...)
  /app\.(get|post|put|delete|patch)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
  // router.get('/path', ...)
  /router\.(get|post|put|delete|patch)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
]

function detectExpress(content: string): DetectedRoute[] {
  const routes: DetectedRoute[] = []
  for (const p of EXPRESS_PATTERNS) {
    let m
    p.lastIndex = 0
    while ((m = p.exec(content)) !== null) {
      routes.push(makeRoute(m[1].toUpperCase(), m[2], ""))
    }
  }
  return routes
}

// --- FastAPI / Python -----------------------------------------------------

const FASTAPI_PATTERNS: RegExp[] = [
  // @router.get("/path")
  /@router\.(get|post|put|delete|patch)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
  // @app.get("/path")
  /@app\.(get|post|put|delete|patch)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
]

function detectFastAPI(content: string): DetectedRoute[] {
  const routes: DetectedRoute[] = []
  for (const p of FASTAPI_PATTERNS) {
    let m
    p.lastIndex = 0
    while ((m = p.exec(content)) !== null) {
      routes.push(makeRoute(m[1].toUpperCase(), m[2], ""))
    }
  }
  return routes
}

// --- NestJS / TypeScript ---------------------------------------------------

const NESTJS_PATTERNS: RegExp[] = [
  // @Get('path')
  /@(Get|Post|Put|Delete|Patch)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
  // @Get()
  /@(Get|Post|Put|Delete|Patch)\s*\(\s*\)/g,
]

function detectNestJS(content: string): DetectedRoute[] {
  const routes: DetectedRoute[] = []
  for (const p of NESTJS_PATTERNS) {
    let m
    p.lastIndex = 0
    while ((m = p.exec(content)) !== null) {
      const method = m[1].toUpperCase()
      const path   = m[2] ?? ""
      routes.push(makeRoute(method, path, ""))
    }
  }
  return routes
}

// --- Laravel / PHP ---------------------------------------------------------

const LARAVEL_PATTERNS: RegExp[] = [
  // Route::get('/path', ...)
  /Route::(get|post|put|delete|patch|any)\s*\(\s*['"]([^'"\s][^'"\)]*)['"]/g,
]

function detectLaravel(content: string): DetectedRoute[] {
  const routes: DetectedRoute[] = []
  for (const p of LARAVEL_PATTERNS) {
    let m
    p.lastIndex = 0
    while ((m = p.exec(content)) !== null) {
      routes.push(makeRoute(m[1].toUpperCase(), m[2], ""))
    }
  }
  return routes
}

// ── Router dispatcher ─────────────────────────────────────────────────────

function detectRoutes(
  content: string,
  filePath: string,
  framework: string,
): DetectedRoute[] {
  const raw = matchFramework(content, framework, filePath)

  // Déduplique sur (method, path)
  const seen = new Set<string>()
  return raw.filter((r) => {
    const key = `${r.method}|${r.path}`
    if (seen.has(key)) return false
    seen.add(key)
    return true
  })
}

function matchFramework(content: string, framework: string, _fp: string): DetectedRoute[] {
  switch (framework) {
    case "express":  return detectExpress(content)
    case "fastapi":  return detectFastAPI(content)
    case "nestjs":   return detectNestJS(content)
    case "laravel":  return detectLaravel(content)
    default:         // inconnu → on scanne tous les patterns pertinents
      return [...detectExpress(content), ...detectFastAPI(content), ...detectNestJS(content), ...detectLaravel(content)]
  }
}

// ── Helpers ──────────────────────────────────────────────────────────────

function makeRoute(
  method: string,
  path: string,
  description: string,
): DetectedRoute {
  return {
    name: "",
    method: method as DetectedRoute["method"],
    path: normalizePath(path),
    headers: [],
    body: "",
    bodyType: "none",
    authRequired: false,
    description,
    sourceFile: "",
  }
}

function normalizePath(path: string): string {
  return path
    .replace(/\$\{[^}]+\}/g, ":param")
    .replace(/:([a-zA-Z_]\w*)/g, ":$1")
}

// ── AI analysis ────────────────────────────────────────────────────────────

export async function analyzeWithAI(
  folderPath: string,
  provider: AIProvider,
  apiKey?: string,
): Promise<SavedProject> {
  const staticProject = await analyzeStatic(folderPath)
  const aiRoutes = await enrichRoutesWithAI(staticProject.routes, provider, apiKey)

  return {
    ...staticProject,
    routes: aiRoutes,
    mode: "ai",
    analyzedAt: new Date().toISOString(),
  }
}

async function enrichRoutesWithAI(
  routes: DetectedRoute[],
  provider: AIProvider,
  apiKey?: string,
): Promise<DetectedRoute[]> {
  if (routes.length === 0) return routes
  if (provider !== "ollama" && !apiKey) return routes

  const promptRoutes = routes.map((route) => `${route.method} ${route.path}`).join("\n")
  const message = `Tu es un assistant qui enrichit une liste de points d'API détectés. Pour chaque route, fournit une description concise, si elle requiert une authentification et le type de corps attendu. Donne uniquement une réponse JSON valide sous la forme d'un tableau d'objets avec les champs : method, path, description, authRequired, bodyType.\n\nRoutes :\n${promptRoutes}`

  try {
    const content = await queryAI(provider, apiKey, message)
    const parsed = parseJsonResponse(content)
    if (!Array.isArray(parsed)) return routes

    const routeMap = new Map(parsed.map((item: any) => [`${item.method} ${item.path}`, item]))
    return routes.map((route) => {
      const match = routeMap.get(`${route.method} ${route.path}`)
      if (!match) return route
      return {
        ...route,
        description: typeof match.description === "string" ? match.description : route.description,
        authRequired: typeof match.authRequired === "boolean" ? match.authRequired : route.authRequired,
        bodyType: match.bodyType === "json" || match.bodyType === "form" ? match.bodyType : route.bodyType,
      }
    })
  } catch {
    return routes
  }
}

function parseJsonResponse(text: string): unknown {
  try {
    return JSON.parse(text)
  } catch {
    const match = text.match(/\{[\s\S]*\}|\[[\s\S]*\]/)
    if (!match) throw new Error("Impossible d'extraire JSON")
    return JSON.parse(match[0])
  }
}

async function queryAI(
  provider: AIProvider,
  apiKey: string | undefined,
  message: string,
): Promise<string> {
  const ollamaConfig = provider === "ollama" ? loadOllamaConfig() : null
  const response = await fetch("/api/proxy-ai", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      provider,
      apiKey,
      model: provider === "anthropic"
        ? "claude-sonnet-4-20250514"
        : provider === "openai"
          ? "gpt-4o"
          : provider === "gemini"
            ? "gemini-2.0-flash"
            : ollamaConfig?.model || "llama2",
      host: ollamaConfig?.host,
      port: ollamaConfig?.port,
      system: "Tu es un assistant qui enrichit la détection de routes API pour un projet. Réponds uniquement avec du JSON valide.",
      message,
    }),
  })

  const data = await response.json()
  if (!response.ok) {
    throw new Error(data.error || "Erreur IA")
  }
  return data.content ?? ""
}

import { clsx, type ClassValue } from 'clsx'
import { twMerge } from 'tailwind-merge'
import { EnvironmentVariable } from '@/hooks/use-request-store'

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

export function interpolate(text: string, variables: EnvironmentVariable[]): string {
  if (!text) return text
  let result = text
  const enabledVars = variables.filter(v => v.enabled && v.key.trim() !== '')

  // Replace each {{KEY}} with the variable value
  enabledVars.forEach(v => {
    const regex = new RegExp(`\\{\\{\\s*${v.key}\\s*\\}\\}`, 'g')
    result = result.replace(regex, v.value)
  })

  return result
}

export function replaceLocalhostPort(url: string, port: number): string {
  if (!url) return url
  return url.replace(/\/\/localhost:\d+/, `//localhost:${port}`)
}

const COLLECTION_LOAD_KEY = "zendeeps-load-collection-request"

export interface PendingCollectionRequest {
  name: string
  method: string
  url: string
  endpoint: string
  headers?: Record<string, string>
  body?: string
  queryParams?: Array<{ key: string; value: string }>
  sendImmediately?: boolean
  collectionId?: string
  background?: boolean
}

export function setPendingCollectionRequest(request: PendingCollectionRequest) {
  try {
    localStorage.setItem(COLLECTION_LOAD_KEY, JSON.stringify(request))
  } catch {}
}

export function getAndClearPendingCollectionRequest(): PendingCollectionRequest | null {
  try {
    const raw = localStorage.getItem(COLLECTION_LOAD_KEY)
    if (raw) {
      localStorage.removeItem(COLLECTION_LOAD_KEY)
      return JSON.parse(raw)
    }
  } catch {}
  return null
}

export async function downloadJson(data: any, filename: string) {
  const content = JSON.stringify(data, null, 2)
  const isTauri = typeof window !== 'undefined' && !!(window as any).__TAURI__

  if (isTauri) {
    try {
      const { save } = await import('@tauri-apps/plugin-dialog')
      const { writeTextFile } = await import('@tauri-apps/plugin-fs')

      const filePath = await save({
        defaultPath: filename.endsWith('.json') ? filename : `${filename}.json`,
        filters: [{ name: 'JSON', extensions: ['json'] }]
      })

      if (filePath) {
        await writeTextFile(filePath, content)
      }
      return
    } catch (err) {
      console.error('Failed to save file using Tauri dialog', err)
      // fallback to browser approach if it fails
    }
  }

  const blob = new Blob([content], { type: "application/json" })
  const url = URL.createObjectURL(blob)
  const a = document.createElement("a")
  a.href = url
  a.download = filename.endsWith(".json") ? filename : `${filename}.json`
  document.body.appendChild(a)
  a.click()
  document.body.removeChild(a)
  URL.revokeObjectURL(url)
}

